import { saveAs } from "file-saver";

/**
 * ===========================================================
 * Utility: exportToCSV
 * -----------------------------------------------------------
 * Description:
 *   Handles exporting one or more table objects into downloadable
 *   CSV files. Used by report components to allow teachers or admins
 *   to export generated report tables for offline use or archiving.
 *
 * Usage:
 *   exportToCSV(tables, disabledCols, disabledRows)
 *
 * Parameters:
 *   @param {Array} tables - Array of report table objects:
 *        [
 *          {
 *            title: "Report Title",
 *            columns: [{ label: "Name", key: "name" }, ...],
 *            rows: [{ name: "Alice", score: 95 }, ...]
 *          },
 *          ...
 *        ]
 *
 *   @param {Array} [disabledCols=[]]
 *        Array of column keys that should be excluded from export.
 *
 *   @param {Array} [disabledRows=[]]
 *        Array of row indices that should be excluded from export.
 *
 * Output:
 *   - Creates one CSV file per table.
 *   - Automatically adds current date suffix to filenames.
 *   - Escapes all fields with quotes for safe CSV formatting.
 *
 * Dependencies:
 *   - file-saver (for creating downloadable files in browser)
 * ===========================================================
 */

export function exportToCSV(tables, disabledCols = [], disabledRows = []) {
  try {
    tables.forEach((table) => {
      // Filter out disabled columns
      const activeColumns = table.columns.filter(
        (c) => !disabledCols.includes(c.key)
      );

      // Extract column headers
      const headers = activeColumns.map((c) => c.label);

      // Filter rows and include only active columns
      const rows = table.rows
        .filter((_, i) => !disabledRows.includes(i))
        .map((r) =>
          activeColumns.map((c) => (r[c.key] !== undefined ? r[c.key] : ""))
        );

      // Build CSV string: join headers + rows with commas and line breaks
      const csvContent = [headers, ...rows]
        .map((r) => r.map((v) => `"${v}"`).join(","))
        .join("\n");

      // Filename includes report title and current date
      const date = new Date().toISOString().slice(0, 10);
      const blob = new Blob([csvContent], {
        type: "text/csv;charset=utf-8;",
      });
      saveAs(blob, `${table.title.replace(/\s+/g, "_")}_${date}.csv`);
    });
  } catch (err) {
    console.error("CSV export failed:", err);
  }
}
