import jsPDF from "jspdf";
import autoTable from "jspdf-autotable";
import logo from "@/store/logo.jpeg";

/**
 * ===========================================================
 * Utility: exportToPDF
 * -----------------------------------------------------------
 * Description:
 *   Converts one or more report tables into a downloadable
 *   PDF document. Automatically adjusts page orientation,
 *   font size, and layout depending on table width and
 *   column count.
 *
 *   Each report table becomes a separate page, with the
 *   company logo and report title displayed at the top.
 *
 * Usage:
 *   exportToPDF(tables, selectedReport, disabledCols, disabledRows)
 *
 * Parameters:
 *   @param {Array} tables
 *        Array of report table objects:
 *        [
 *          {
 *            title: "Table Title",
 *            columns: [{ label: "Header", key: "headerKey" }, ...],
 *            rows: [{ headerKey: "Value", ... }, ...]
 *          },
 *          ...
 *        ]
 *
 *   @param {String} [selectedReport="Untitled Report"]
 *        Report title used in the file name and header.
 *
 *   @param {Array|Array[]} [disabledCols=[]]
 *        Array of disabled column keys.
 *        - Can be a single array for all tables, or an array of arrays
 *          matching each table’s column configuration.
 *
 *   @param {Array|Array[]} [disabledRows=[]]
 *        Array of disabled row indices.
 *        - Can also be per-table array of arrays.
 *
 * Output:
 *   - Generates a multi-page PDF file named:
 *       Report_<ReportName>_<Date>.pdf
 *   - Each table rendered on a new page with consistent branding.
 *   - Alerts user if too many columns are present (>17).
 *
 * Dependencies:
 *   - jspdf (for document creation)
 *   - jspdf-autotable (for rendering tables)
 *   - file in @/store/logo.jpeg for header logo
 * ===========================================================
 */

export async function exportToPDF(
  tables,
  selectedReport = "Untitled Report",
  disabledCols = [],
  disabledRows = []
) {
  try {
    if (!tables || tables.length === 0) {
      console.warn("No tables to export");
      return;
    }

    // -----------------------------------------------------------
    // Determine layout based on maximum number of active columns
    // -----------------------------------------------------------
    const maxColumns = Math.max(
      ...tables.map((t, i) =>
        t.columns
          ? t.columns.filter(
              (c) =>
                !(Array.isArray(disabledCols[i])
                  ? disabledCols[i].includes(c.key)
                  : (disabledCols || []).includes(c.key))
            ).length
          : 0
      )
    );

    // Limit column width for PDF clarity
    if (maxColumns >= 18) {
      alert("Table too wide for PDF export. Please hide some columns.");
      return;
    }

    // Orientation: landscape for wide tables, portrait otherwise
    const orientation = maxColumns > 8 ? "landscape" : "portrait";
    const doc = new jsPDF({ orientation });

    // -----------------------------------------------------------
    // Dynamically scale font size based on number of columns
    // -----------------------------------------------------------
    let fontSize = 12;
    if (maxColumns <= 8) fontSize = 12;
    else if (maxColumns <= 11) fontSize = 10;
    else if (maxColumns <= 13) fontSize = 9;
    else if (maxColumns <= 15) fontSize = 8;
    else fontSize = 7; // up to 17 columns

    // -----------------------------------------------------------
    // Load logo image for header (wait for async load)
    // -----------------------------------------------------------
    const img = new Image();
    img.src = logo;
    await new Promise((resolve) => {
      img.onload = () => resolve();
    });

    // -----------------------------------------------------------
    // Render each table on a new PDF page
    // -----------------------------------------------------------
    tables.forEach((table, tIdx) => {
      if (tIdx > 0) doc.addPage(); // new page for each table

      // Add logo + header
      doc.addImage(img, "JPEG", 14, 10, 25, 12);
      doc.setFontSize(14);
      doc.text(selectedReport || "Untitled Report", 44, 18);
      doc.setFontSize(12);
      doc.text(table.title, 14, 30);

      // Per-table disabled column/row handling
      const disabledColArray = Array.isArray(disabledCols[tIdx])
        ? disabledCols[tIdx]
        : disabledCols || [];
      const disabledRowArray = Array.isArray(disabledRows[tIdx])
        ? disabledRows[tIdx]
        : disabledRows || [];

      // Build headers and rows excluding disabled data
      const activeColumns =
        table.columns && table.columns.length
          ? table.columns.filter((c) => !disabledColArray.includes(c.key))
          : [];
      const headers = activeColumns.map((c) => c.label);

      const filteredRows =
        table.rows && table.rows.length
          ? table.rows.filter((_, i) => !disabledRowArray.includes(i))
          : [];
      const rows = filteredRows.map((r) =>
        activeColumns.map((c) => r[c.key] ?? "")
      );

      // -----------------------------------------------------------
      // Render the table using jsPDF-AutoTable
      // -----------------------------------------------------------
      autoTable(doc, {
        startY: 34,
        head: [headers],
        body: rows,
        styles: { fontSize: fontSize, cellPadding: 1.5 },
        headStyles: { fillColor: [66, 139, 202], fontSize: fontSize },
        margin: { top: 30 },
      });
    });

    // -----------------------------------------------------------
    // Save final PDF to file
    // -----------------------------------------------------------
    const date = new Date().toISOString().slice(0, 10);
    doc.save(`Report_${selectedReport.replace(/\s+/g, "_")}_${date}.pdf`);
  } catch (err) {
    console.error("PDF export failed:", err);
  }
}
