<template>
  <div class="course-finder hscroll">
    <!-- ====== FILTER BAR ====== -->
    <div class="filters">
      <!-- Teacher -->
      <div class="filter-item">
        <label>Teacher</label>
        <el-select
          v-model="filters.teacher"
          filterable
          clearable
          placeholder="Type or select teacher"
          class="compact-input"
        >
          <el-option
            v-for="t in availableTeachers"
            :key="t"
            :label="t"
            :value="t"
          />
        </el-select>
      </div>

      <!-- Students -->
      <div class="filter-item">
        <label>Students</label>
        <el-select
          v-model="filters.students"
          multiple
          filterable
          clearable
          placeholder="Type or select students"
          class="compact-input"
        >
          <el-option
            v-for="s in availableStudents"
            :key="s"
            :label="s"
            :value="s"
          />
        </el-select>
      </div>

      <!-- Subject -->
      <div class="filter-item">
        <label>Subject</label>
        <el-select
          v-model="filters.subjects"
          multiple
          filterable
          clearable
          placeholder="Type or select subjects"
          class="compact-input"
        >
          <el-option
            v-for="sub in availableSubjects"
            :key="sub"
            :label="sub"
            :value="sub"
          />
        </el-select>
      </div>

      <!-- Level -->
      <div class="filter-item">
        <label>Level</label>
        <el-select
          v-model="filters.levels"
          multiple
          filterable
          clearable
          placeholder="Type or select levels"
          class="compact-input"
        >
          <el-option
            v-for="lvl in availableLevels"
            :key="lvl"
            :label="lvl"
            :value="lvl"
          />
        </el-select>
      </div>

      <!-- Date Range -->
      <div class="filter-item">
        <label>Date Range</label>
        <el-date-picker
          v-model="filters.dateRange"
          type="daterange"
          start-placeholder="Start date"
          end-placeholder="End date"
          range-separator="To"
          size="small"
          class="compact-input"
        />
      </div>

      <!-- Buttons row -->
      <div class="filter-actions">
        <el-button @click="resetFilters">Reset</el-button>
        <el-button type="primary" @click="generateCourseReport">Generate</el-button>
        <el-button @click="closeFinder">Close</el-button>
      </div>
    </div>

    <!-- ====== COURSE RESULTS TABLE ====== -->
    <div class="table-wrapper">
      <el-table
        ref="courseTable"
        :data="filteredCourses"
        stripe
        highlight-current-row
        @row-click="selectCourse"
        style="width: 100%"
      >
        <el-table-column prop="course_id" label="Course ID" width="140" />
        <el-table-column prop="teachers" label="Teachers" />
        <el-table-column prop="students" label="Students" />
        <el-table-column prop="subjects" label="Subjects" />
        <el-table-column prop="levels" label="Levels" />
        <el-table-column prop="start" label="Start" width="120" />
        <el-table-column prop="end" label="End" width="120" />
        <el-table-column prop="total_classes" label="Classes" width="110" />
      </el-table>
    </div>
  </div>
</template>

<script>
import combinedData from "@/data/combined.json";

export default {
  name: "CourseFinder",

  props: {
    includeCancelled: {
      type: Boolean,
      default: false,
    },
  },

  data() {
    return {
      allClasses: combinedData,
      filters: {
        teacher: null,
        students: [],
        subjects: [],
        levels: [],
        dateRange: [],
      },
      selectedCourse: null,
    };
  },

  computed: {
    filteredClasses() {
      return this.allClasses.filter((c) => {
        const startDate = new Date(c.scheduled_start);
        if (
          this.filters.teacher &&
          !c.participants.some(
            (p) => p.isteacher && p.username === this.filters.teacher
          )
        )
          return false;
        if (
          this.filters.students.length &&
          !c.participants.some(
            (p) => !p.isteacher && this.filters.students.includes(p.username)
          )
        )
          return false;
        if (
          this.filters.subjects.length &&
          !this.filters.subjects.includes(c.class_lang)
        )
          return false;
        if (
          this.filters.levels.length &&
          !this.filters.levels.includes(c.lang_level)
        )
          return false;
        if (
          this.filters.dateRange[0] &&
          startDate < new Date(this.filters.dateRange[0])
        )
          return false;
        if (
          this.filters.dateRange[1] &&
          startDate > new Date(this.filters.dateRange[1])
        )
          return false;
        return true;
      });
    },

    availableTeachers() {
      const set = new Set();
      this.filteredClasses.forEach((c) =>
        c.participants
          .filter((p) => p.isteacher)
          .forEach((p) => set.add(p.username))
      );
      return Array.from(set).sort();
    },
    availableStudents() {
      const set = new Set();
      this.filteredClasses.forEach((c) =>
        c.participants
          .filter((p) => !p.isteacher)
          .forEach((p) => set.add(p.username))
      );
      return Array.from(set).sort();
    },
    availableSubjects() {
      return Array.from(
        new Set(this.filteredClasses.map((c) => c.class_lang).filter(Boolean))
      ).sort();
    },
    availableLevels() {
      return Array.from(
        new Set(this.filteredClasses.map((c) => c.lang_level).filter(Boolean))
      ).sort();
    },

    filteredCourses() {
      const courses = {};
      this.filteredClasses.forEach((c) => {
        if (!courses[c.course_id]) {
          courses[c.course_id] = {
            course_id: c.course_id,
            teachers: new Set(),
            students: new Set(),
            subjects: new Set(),
            levels: new Set(),
            start: c.scheduled_start,
            end: c.scheduled_start,
            total_classes: 0,
          };
        }
        const course = courses[c.course_id];
        course.total_classes++;
        if (new Date(c.scheduled_start) < new Date(course.start))
          course.start = c.scheduled_start;
        if (new Date(c.scheduled_start) > new Date(course.end))
          course.end = c.scheduled_start;
        c.participants.forEach((p) => {
          if (p.isteacher) course.teachers.add(p.username);
          else course.students.add(p.username);
        });
        if (c.class_lang) course.subjects.add(c.class_lang);
        if (c.lang_level) course.levels.add(c.lang_level);
      });

      return Object.values(courses).map((c) => ({
        course_id: c.course_id,
        teachers: Array.from(c.teachers).join(", "),
        students: Array.from(c.students).join(", "),
        subjects: Array.from(c.subjects).join(", "),
        levels: Array.from(c.levels).join(", "),
        start: (c.start || "").split(" ")[0],
        end: (c.end || "").split(" ")[0],
        total_classes: c.total_classes,
      }));
    },
  },

  methods: {
    resetFilters() {
      this.filters = {
        teacher: null,
        students: [],
        subjects: [],
        levels: [],
        dateRange: [],
      };
      this.selectedCourse = null;
    },

    /** Track the clicked course row */
    selectCourse(row) {
      this.selectedCourse = row;
      this.$refs.courseTable.setCurrentRow(row);
      this.$emit("select-course", row.course_id); // notify parent immediately
    },

    /** Generate report for selected or single filtered course */
    generateCourseReport() {
      const n = this.filteredCourses.length;

      if (this.selectedCourse) {
        this.$emit("generate", this.selectedCourse.course_id);
        this.$message({
          message: `Generating report for course ${this.selectedCourse.course_id}`,
          type: "success",
        });
        return;
      }

      if (n === 1) {
        const id = this.filteredCourses[0].course_id;
        this.$emit("generate", id);
        this.$message({
          message: `Automatically generating report for course ${id}`,
          type: "success",
        });
      } else if (n > 1) {
        this.$message({
          message: `Found ${n} matching courses. Please click a row before generating.`,
          type: "info",
        });
      } else {
        this.$message({
          message: "No matching courses found.",
          type: "warning",
        });
      }
    },

    /** Close and notify parent to hide CourseFinder */
    closeFinder() {
      this.$emit("cancel");
    },
  },
};
</script>

