<!--
  ==========================================================
  Component: ReportRenderer.vue
  Description:
    Displays one or more report tables based on the data emitted by report settings components.
    Supports tabbed views, row/column disabling for selective exports, and multiple export formats
    (CSV, Excel, PDF).

  Responsibilities:
    - Render report tables dynamically from JSON-based data.
    - Allow users to toggle visibility of specific rows and columns.
    - Control which data is included in exported files.
    - Automatically disable PDF export if the table is too wide to fit legibly.

  Export Utilities:
    - exportExcel.js   → XLSX (Excel) export
    - exportCSV.js     → CSV export
    - exportPDF.js     → PDF export with width-sensitive formatting

  Notes:
    - This component is presentation-focused; it receives pre-formatted data.
    - It applies UI interactivity (hover, click, disable) and delegates export logic to helpers.
  ==========================================================
-->

<template>
  <div class="report-wrapper">
    <div class="report-topbar">
      <div class="report-header">
        <h2 class="table-title">Report Preview</h2>
      </div>

      <!-- ======= EXPORT BUTTONS ======= -->
      <div class="export-buttons">
        <el-button size="small" type="primary" @click="handleExportExcel">
          <i class="fas fa-file-excel"></i>
        </el-button>
        <el-button size="small" type="primary" @click="handleExportCSV">
          <i class="fas fa-file-csv"></i>
        </el-button>

        <!-- PDF Export: disabled if table too wide -->
        <el-tooltip v-if="isPDFExportTooWide" content="Table too wide for PDF export. Hide some columns.">
          <span>
            <el-button size="small" type="primary" disabled>
              <i class="fas fa-file-pdf"></i>
            </el-button>
          </span>
        </el-tooltip>
        <el-button
          v-else
          size="small"
          type="primary"
          @click="handleExportPDF"
        >
          <i class="fas fa-file-pdf"></i>
        </el-button>
      </div>
    </div>

    <!-- ======= REPORT TABLES ======= -->
    <div class="report-renderer">
      <!-- Multi-table layout (tabbed) -->
      <el-tabs
        v-if="tables.length > 1"
        v-model="activeTab"
        type="border-card"
        class="report-tabs"
      >
        <el-tab-pane
          v-for="(table, index) in tables"
          :key="index"
          :label="table.title"
          :name="index.toString()"
        >
          <div class="scroll-wrapper">
            <div class="table-container" :class="{ 'has-hscroll': needsHScroll(table, index) }">
              <!-- Table Renderer -->
              <el-table
                v-if="table.rows && table.columns"
                :data="table.rows"
                border
                :fit="true"
                :max-height="table.format?.table?.scrollable ? table.format.table.maxHeight : null"
                :header-cell-style="getHeaderStyle"
                :cell-style="getCellStyle"
                :style="getTableStyle(table)"
                :key="index"
              >
                <!-- Dynamic columns -->
                <el-table-column
                  v-for="(col, colIdx) in table.columns"
                  :key="col.key"
                  :prop="col.key"
                  :label="col.label"
                  :width="col.width"
                  align="center"
                  :show-overflow-tooltip="col.showOverflowTooltip || col.key === 'description'"
                >
                  <!-- Clickable Header (toggles columns on/off) -->
                  <template #header>
                    <el-tooltip
                      v-if="col.tooltip"
                      :content="col.tooltip"
                      placement="top"
                      effect="dark"
                    >
                      <div
                        class="clickable-header"
                        :class="{
                          active: hoveredCol === col.key,
                          disabled: isColDisabled(index, col.key)
                        }"
                        @mouseover="hoveredCol = col.key"
                        @mouseleave="hoveredCol = null"
                        @click="toggleColumn(index, col.key)"
                      >
                        {{ col.label }}
                      </div>
                    </el-tooltip>
                    <div
                      v-else
                      class="clickable-header"
                      :class="{
                        active: hoveredCol === col.key,
                        disabled: isColDisabled(index, col.key)
                      }"
                      @mouseover="hoveredCol = col.key"
                      @mouseleave="hoveredCol = null"
                      @click="toggleColumn(index, col.key)"
                    >
                      {{ col.label }}
                    </div>
                  </template>

                  <!-- First Column: Rows clickable to toggle visibility -->
                  <template v-if="colIdx === 0" #default="scope">
                    <el-tooltip
                      v-if="scope.row.tooltip"
                      :content="scope.row.tooltip"
                      placement="right"
                      effect="dark"
                    >
                      <div
                        class="clickable-rowcell"
                        :class="{ disabled: isRowDisabled(index, scope.$index) }"
                        @click="toggleRow(index, scope.$index)"
                        style="cursor:pointer;"
                      >
                        {{ scope.row[col.key] }}
                      </div>
                    </el-tooltip>
                    <div
                      v-else
                      class="clickable-rowcell"
                      :class="{ disabled: isRowDisabled(index, scope.$index) }"
                      @click="toggleRow(index, scope.$index)"
                      style="cursor:pointer;"
                    >
                      {{ scope.row[col.key] }}
                    </div>
                  </template>

                  <!-- Other Columns: visually mark disabled cells -->
                  <template v-else #default="scope">
                    <span
                      :class="{ disabled: isColDisabled(index, col.key) || isRowDisabled(index, scope.$index) }"
                    >
                      {{ scope.row[col.key] }}
                    </span>
                  </template>
                </el-table-column>
              </el-table>
            </div>
          </div>
        </el-tab-pane>
      </el-tabs>

      <!-- Single-table layout -->
      <div
        v-else
        v-for="(table, index) in tables"
        :key="index"
      >
        <h3 class="table-subtitle">{{ table.title }}</h3>
        <div class="scroll-wrapper">
          <div class="table-container" :class="{ 'has-hscroll': needsHScroll(table, index) }">
            <!-- Table structure same as above -->
            <el-table
              v-if="table.rows && table.columns"
              :data="table.rows"
              border
              :fit="true"
              :max-height="table.format?.table?.scrollable ? table.format.table.maxHeight : null"
              :header-cell-style="getHeaderStyle"
              :cell-style="getCellStyle"
              :style="getTableStyle(table)"
              :key="index"
            >
              <el-table-column
                v-for="(col, colIdx) in table.columns"
                :key="col.key"
                :prop="col.key"
                :label="col.label"
                :width="col.width"
                align="center"
                :show-overflow-tooltip="col.showOverflowTooltip || col.key === 'description'"
              >
                <template #header>
                  <el-tooltip
                    v-if="col.tooltip"
                    :content="col.tooltip"
                    placement="top"
                    effect="dark"
                  >
                    <div
                      class="clickable-header"
                      :class="{
                        active: hoveredCol === col.key,
                        disabled: isColDisabled(index, col.key)
                      }"
                      @mouseover="hoveredCol = col.key"
                      @mouseleave="hoveredCol = null"
                      @click="toggleColumn(index, col.key)"
                    >
                      {{ col.label }}
                    </div>
                  </el-tooltip>
                  <div
                    v-else
                    class="clickable-header"
                    :class="{
                      active: hoveredCol === col.key,
                      disabled: isColDisabled(index, col.key)
                    }"
                    @mouseover="hoveredCol = col.key"
                    @mouseleave="hoveredCol = null"
                    @click="toggleColumn(index, col.key)"
                  >
                    {{ col.label }}
                  </div>
                </template>

                <!-- First column: clickable rows -->
                <template v-if="colIdx === 0" #default="scope">
                  <el-tooltip
                    v-if="scope.row.tooltip"
                    :content="scope.row.tooltip"
                    placement="right"
                    effect="dark"
                  >
                    <div
                      class="clickable-rowcell"
                      :class="{ disabled: isRowDisabled(index, scope.$index) }"
                      @click="toggleRow(index, scope.$index)"
                      style="cursor:pointer;"
                    >
                      {{ scope.row[col.key] }}
                    </div>
                  </el-tooltip>
                  <div
                    v-else
                    class="clickable-rowcell"
                    :class="{ disabled: isRowDisabled(index, scope.$index) }"
                    @click="toggleRow(index, scope.$index)"
                    style="cursor:pointer;"
                  >
                    {{ scope.row[col.key] }}
                  </div>
                </template>

                <!-- Other columns: shade disabled cells -->
                <template v-else #default="scope">
                  <span
                    :class="{ disabled: isColDisabled(index, col.key) || isRowDisabled(index, scope.$index) }"
                  >
                    {{ scope.row[col.key] }}
                  </span>
                </template>
              </el-table-column>
            </el-table>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import { exportToExcel } from "@/utils/exportExcel";
import { exportToCSV } from "@/utils/exportCSV";
import { exportToPDF } from "@/utils/exportPDF";

export default {
  name: "ReportRenderer",

  props: {
    selectedReport: {
      type: String,
      default: "Untitled Report"
    },
    tableData: {
      type: [Array, Object],
      default: () => [],
    },
  },

  data() {
    return {
      // Holds one or more report tables (normalized to array)
      tables: Array.isArray(this.tableData)
        ? this.tableData
        : this.tableData
        ? [this.tableData]
        : [],

      // Track user-disabled columns and rows (per table)
      disabledCols: [],
      disabledRows: [],

      hoveredRow: null,
      hoveredCol: null,
      activeTab: "0",
    };
  },

  watch: {
    /**
     * Reactively updates internal state when new report data is passed in.
     * Ensures disabled states are reset and tables are normalized to array form.
     */
    tableData(newVal) {
      if (!newVal) {
        this.tables = [];
        this.disabledCols = [];
        this.disabledRows = [];
        return;
      }
      const tablesArray = Array.isArray(newVal) ? newVal : [newVal];
      this.disabledCols = tablesArray.map(() => []);
      this.disabledRows = tablesArray.map(() => []);
      this.tables = tablesArray;
    }
  },

  computed: {
    /**
     * Determines whether PDF export should be disabled due to excessive column count.
     * PDF export is blocked when 18 or more visible columns exist in any table.
     */
    isPDFExportTooWide() {
      return this.tables.some((table, tIdx) => {
        const disables = this.disabledCols[tIdx] || [];
        const enabledColumns = (table.columns || []).filter(col => !disables.includes(col.key));
        return enabledColumns.length >= 18;
      });
    }
  },

  methods: {
    /** Returns true if a specific column is currently disabled. */
    isColDisabled(idx, key) {
      return (this.disabledCols[idx] || []).includes(key);
    },

    /** Returns true if a specific row is currently disabled. */
    isRowDisabled(idx, rowIdx) {
      return (this.disabledRows[idx] || []).includes(rowIdx);
    },

    /**
     * Toggles a column’s enabled/disabled state.
     * @param {Number} idx - Table index
     * @param {String} key - Column key to toggle
     */
    toggleColumn(idx, key) {
      const arr = this.disabledCols[idx] ? [...this.disabledCols[idx]] : [];
      const i = arr.indexOf(key);
      if (i >= 0) arr.splice(i, 1);
      else arr.push(key);
      this.$set(this.disabledCols, idx, arr);
      this.hoveredCol = null;
    },

    /**
     * Toggles a row’s enabled/disabled state.
     * @param {Number} idx - Table index
     * @param {Number} rowIdx - Row index to toggle
     */
    toggleRow(idx, rowIdx) {
      const arr = this.disabledRows[idx] ? [...this.disabledRows[idx]] : [];
      const i = arr.indexOf(rowIdx);
      if (i >= 0) arr.splice(i, 1);
      else arr.push(rowIdx);
      this.$set(this.disabledRows, idx, arr);
    },

    /**
     * Determines if a table needs horizontal scrolling.
     * Based on either explicit formatting or column count.
     */
    needsHScroll(table, index) {
      const colCount = table.columns.length;
      const forced = table?.format?.table?.forceHScroll === true;
      const maxVisible = table?.format?.table?.maxVisibleColumns ?? 8;
      return forced || colCount > maxVisible;
    },

    /**
     * Calculates inline width styles for tables.
     * Ensures wide tables remain scrollable while compact tables stretch full width.
     */
    getTableStyle(table) {
      const colWidths = (table.columns || []).map(c => c.width || 140);
      const minW = colWidths.reduce((a, c) => a + c, 0) + "px";
      if ((table.columns || []).length > 8 || table?.format?.table?.scrollable) {
        return { minWidth: minW, width: "auto" };
      }
      return { width: "100%" };
    },

    /**
     * Returns dynamic header styling, including hover and disabled states.
     */
    getHeaderStyle({ column }) {
      if (!column) return {};
      let background = "#f9fafb";
      const colKey = column.property || "";
      const index = parseInt(this.activeTab, 10);
      const isDisabled = this.isColDisabled(index, colKey);
      const isHovered = this.hoveredCol === colKey;
      if (isHovered) background = "#e0f2fe";
      if (isDisabled && !isHovered) background = "#f3f4f6";
      return {
        fontWeight: "700",
        textAlign: "center",
        background,
        color: isDisabled ? "#9ca3af" : "#111",
        transition: "background 0.2s, color 0.2s"
      };
    },

    /**
     * Returns dynamic cell styling based on whether the cell’s row or column is disabled.
     */
    getCellStyle({ rowIndex, column }) {
      if (!column) return {};
      const colKey = column.property || "";
      const idx = parseInt(this.activeTab, 10);
      const isDisabledRow = this.isRowDisabled(idx, rowIndex);
      const isDisabledCol = this.isColDisabled(idx, colKey);
      return {
        textAlign: "center",
        fontWeight: "400",
        color: isDisabledRow || isDisabledCol ? "#9ca3af" : "#111",
        background: isDisabledRow || isDisabledCol ? "#f3f4f6" : "#fff",
        transition: "background 0.2s, color 0.2s"
      };
    },

    /**
     * Creates filtered table data containing only enabled rows and columns.
     * This ensures exports only include what’s currently visible to the user.
     * @returns {Array} Array of table objects ready for export.
     */
    getExportTables() {
      return this.tables.map((table, i) => {
        const enabledCols = table.columns.filter(col => !this.isColDisabled(i, col.key));
        const enabledRows = table.rows.filter((row, rowIdx) => !this.isRowDisabled(i, rowIdx));
        return {
          ...table,
          columns: enabledCols,
          rows: enabledRows,
        };
      });
    },

    /** Handles export to Excel format using SheetJS utility. */
    handleExportExcel() {
      exportToExcel(this.getExportTables());
    },

    /** Handles export to CSV format. */
    handleExportCSV() {
      exportToCSV(this.getExportTables());
    },

    /** Handles export to PDF format using jsPDF + autoTable. */
    async handleExportPDF() {
      await exportToPDF(this.getExportTables(), this.selectedReport);
    }
  }
};
</script>

