<!--
  ==========================================================
  Component: App.vue
  Description:
    Main entry point and layout controller for the LearnCube Reporting Dashboard prototype.
    Handles top-level state, report selection, data flow between report settings and renderer,
    and manages the global Settings drawer visibility.

  Dependencies:
    - Element UI components for layout, forms, and interactivity.
    - ReportRenderer.vue for displaying generated report tables.
    - Settings.vue for global configuration options.
    - Report vue components as report-specific settings panels.

  Data Flow:
    1. User selects a report type from the toolbar dropdown.
    2. The corresponding report settings component is rendered in the left panel.
    3. When "Generate Report" is triggered in that component, formatted data is emitted upward.
    4. This component (App.vue) receives the data and passes it to ReportRenderer.vue.
  ==========================================================
-->

<template>
  <div id="app" class="page">
    <!-- ======= TOP TOOLBAR ======= -->
    <el-header height="64px" class="header">
      <div class="header-inner">
        <!-- Left: icon + title -->
        <div class="header-left">
          <i class="el-icon-house"></i>
          <span class="title">REPORTS</span>
          <div class="flex-1"></div>
        </div>

        <!-- Right: filters split into two groups -->
        <div class="header-right">
          <!-- Primary filters (left group): report type selector -->
          <div class="filters-primary">
            <el-select v-model="selectedReport" placeholder="Report Type" size="small">
              <el-option
                v-for="rt in reportTypes"
                :key="rt.value"
                :label="rt.label"
                :value="rt.value"
              />
            </el-select>
          </div>

          <!-- Secondary filters (right group): date, timezone, etc. -->
          <div class="filters-secondary">
            <!-- More button toggles the second row of filters -->
            <el-button
              :type="showMoreFilters ? 'primary' : 'default'"
              size="small"
              @click="toggleMore"
            >
              More Filters
            </el-button>
            <el-select v-model="selectedTimezone" placeholder="Europe/Paris" size="small"></el-select>
            <el-date-picker
              v-model="dateRange"
              type="daterange"
              range-separator="To"
              size="small"
              :picker-options="{ disabledDate: disableFutureDates }"
            />
            <el-button
              type="primary"
              icon="el-icon-search"
              size="small"
              @click="handleSearchClick"
            ></el-button>
          </div>
        </div>
      </div>
    </el-header>

    <!-- ======= EXPANDABLE MORE FILTERS ROW ======= -->
    <transition name="slidefade">
      <div v-show="showMoreFilters" class="more-row">
        <!-- Disabled placeholder selects (UI stubs for now) -->
        <el-select v-model="dummyValue" disabled plain placeholder="Teacher"></el-select>
        <el-select v-model="dummyValue" disabled plain placeholder="Student"></el-select>
        <el-select v-model="dummyValue" disabled plain placeholder="Company"></el-select>
        <el-select v-model="dummyValue" disabled plain placeholder="Additional Filter"></el-select>
        <el-select v-model="dummyValue" disabled plain placeholder="Additional Filter"></el-select>
        <el-select v-model="dummyValue" disabled plain placeholder="Additional Filter"></el-select>
      </div>
    </transition>

    <!-- ======= MAIN CONTENT ======= -->
    <div class="content-wrap">
      <div class="two-col">
        <!-- LEFT PANEL: Report-specific settings -->
        <div class="panel left">
          <component
            v-if="currentSettingsComponent"
            :is="currentSettingsComponent"
            ref="settingsPane"
            @report-generated="handleReportGenerated"
            @open-course-finder="showCourseFinder = true"
          />
          <div v-else class="placeholder">Select a report type</div>
        </div>

        <!-- RIGHT PANEL: Report preview and exports -->
        <div class="panel right">
        <template v-if="showCourseFinder">
          <CourseFinder
            :data="require('@/data/combined.json').default || combinedData"
            :include-cancelled="true"
            @cancel="showCourseFinder = false"
            @select-course="handleCoursePicked"
            @generate="handleCoursePickedAndGenerate"
          />
        </template>
        <template v-else>
          <ReportRenderer
            v-if="generatedReport && generatedReport.length"
            :table-data="generatedReport"
          />
          <div v-else class="placeholder">No report generated</div>
        </template>
      </div>

      </div>
    </div>

    <!-- ======= SETTINGS DRAWER ======= -->
    <el-drawer
      title="Settings"
      :visible.sync="drawerVisible"
      direction="rtl"
      size="30%"
    >
      <Settings />
    </el-drawer>

    <!-- Floating Settings Tab: opens the drawer -->
    <div class="settings-tab" @click="drawerVisible = true">
      <i class="el-icon-setting"></i>
    </div>

  </div>
</template>

<script>

import axios from "axios";

import reportTypes from "@/data/reportTypes.json";
import combinedData from "@/data/combined.json";

import Settings from "@/components/Settings.vue";
import ReportRenderer from "@/components/ReportRenderer.vue";
import CourseFinder from "@/components/CourseFinder.vue";

import OverviewReport from "@/components/reports/OverviewReport.vue";
import ClassListReport from "@/components/reports/ClassListReport.vue";
import TeacherReport from "@/components/reports/TeacherReport.vue";
import CourseReport from "@/components/reports/CourseReport.vue";
import StudentReport from "@/components/reports/StudentReport.vue";
import HourCountReport from "@/components/reports/HourCountReport.vue";



export default {
  name: "App",
  components: { Settings, ReportRenderer, CourseFinder, OverviewReport, ClassListReport, TeacherReport, CourseReport, StudentReport, HourCountReport },

  data() {
    return {
      drawerVisible: false, // Controls visibility of the global settings drawer
      selectedReport: "", // Currently selected report type (overview, class list, etc.)
      selectedTimezone: "", // Placeholder for timezone filter
      reportTypes, // List of available report types (from JSON)
      dateRange: [], // Selected date range for filtering reports
      showMoreFilters: false, // Toggles visibility of expanded filter row
      dummyValue: "", // Bound to disabled placeholder filters
      generatedReport: null, // Holds the processed report data ready for rendering
      showCourseFinder: false,
    };
  },

  methods: {
    /**
     * Toggles visibility of the secondary filter row.
     */
    toggleMore() {
      this.showMoreFilters = !this.showMoreFilters;
    },

    /**
     * Handles report data emitted by a report settings component.
     * Accepts both single-table and multi-table data structures.
     * @param {Object|Array} data - The generated report data.
     */
    handleReportGenerated(data) {
      console.log("Received report data:", data);
      // Normalize data to always be an array of tables for ReportRenderer
      this.generatedReport = Array.isArray(data) ? data : [data];
    },

    /** Receive a courseId from CourseFinder and push it into the current settings pane (CourseReport). */
    handleCoursePicked(courseId) {
      // Guard: only call if the active settings pane exposes setSelectedCourse()
      if (this.$refs.settingsPane && typeof this.$refs.settingsPane.setSelectedCourse === 'function') {
        this.$refs.settingsPane.setSelectedCourse(courseId);
      }
    },

    /** After choosing a courseId, also request generation (lets the user click once). */
    handleCoursePickedAndGenerate(courseId) {
      this.handleCoursePicked(courseId);
      this.showCourseFinder = false; // close finder
      // Trigger the settings pane's generate button programmatically if you like.
      // If you prefer manual click, omit the line below.
      if (this.$refs.settingsPane && typeof this.$refs.settingsPane.generateReport === 'function') {
        this.$refs.settingsPane.generateReport();
      }
    },

    /** restrict date picker to past only. */
    disableFutureDates(date) {
      const today = new Date();
      today.setHours(0, 0, 0, 0);     // start of today
      return date.getTime() >= today.getTime(); // disable today + future
    },

    /** Used to handle search and filters for back end API functions. */
    async handleSearchClick() {
      console.log("Selected date range:", this.dateRange);

      if (Array.isArray(this.dateRange) && this.dateRange.length === 2) {
        const [start, end] = this.dateRange;

        // Format as YYYY-MM-DD for backend
        const startStr = this.formatDate(start);
        const endStr = this.formatDate(end);

        console.log("Sending to backend:", startStr, "→", endStr);

        try {
          const response = await axios.post("http://127.0.0.1:8000/api/dates/", {
            start_date: startStr,
            end_date: endStr,
          });

          console.log("Backend response:", response.data);
          alert("✅ Sent successfully! Check your Django terminal.");

        } catch (error) {
          console.error("Error sending dates:", error);
          alert("❌ Error sending to backend. See console for details.");
        }

      } else {
        console.log("No date range selected yet.");
        alert("Please select a date range first.");
      }
    },

    /** Helper: format JS Date into YYYY-MM-DD */
    formatDate(date) {
      const d = new Date(date);
      const year = d.getFullYear();
      const month = String(d.getMonth() + 1).padStart(2, "0");
      const day = String(d.getDate()).padStart(2, "0");
      return `${year}-${month}-${day}`;
    },



  },

  computed: {
    /**
     * Determines which report settings component should be displayed
     * based on the selected report type from the top toolbar.
     * @returns {String|null} Component name or null if none selected.
     */
    currentSettingsComponent() {
      switch (this.selectedReport) {
        case "overview":
          return "OverviewReport";
        case "classList":
          return "ClassListReport";
        case "teacherReport":
          return "TeacherReport";
        case "courseReport":
          return "courseReport";
        case "studentReport":
          return "studentReport";
        case "hourCountReport":
          return "hourCountReport";
        default:
          return null;
      }
    },
  },
};
</script>

