<template>
  <div class="teacher-report-settings">
    <h3 class="title">Teacher Report</h3>

    <!-- ======= FORM CONTROLS ======= -->
    <el-form
      label-position="left"
      class="settings-form"
    >
      <!-- Options: split class tables and filter to written feedback -->
      <el-form-item>
        <div class="label-above-checkbox">
            <span>Separate Private and Group Classes</span>
            <el-checkbox v-model="separateTables" size="small"></el-checkbox>
        </div>

        <div class="label-above-checkbox">
            <span>Written Student Feedback Only</span>
            <el-checkbox v-model="writtenFeedbackOnly" size="small"></el-checkbox>
        </div>
      </el-form-item>

      <!-- Generate button -->
      <el-form-item>
        <el-button type="primary" size="medium" @click="generateReport">
            Generate Report
        </el-button>
      </el-form-item>

    </el-form>
  </div>
</template>

<script>
/**
 * ===========================================================
 * Component: TeacherReport.vue
 * Description:
 *   Configuration panel and builders for teacher-focused reports.
 *   Depending on user options, outputs:
 *     - One combined "Teachers" table (all classes), OR
 *     - Separate "Private Classes" and "Group Classes" tables,
 *     - Plus a "Student Feedback" table (optionally only written).
 *
 * Data Flow:
 *   - Reads from users.json (teacher aggregates) and combined.json (class sessions).
 *   - Aggregates/derives teacher metrics via collectClassMetrics().
 *   - Builds standardized table objects (title, columns, rows, format).
 *   - Emits "report-generated" with an array of tables to parent.
 * ===========================================================
 */

import usersData from "@/data/users.json";
import combinedData from "@/data/combined.json";

// Helper: left-pad single digits with 0
function pad(n) {
  return n < 10 ? "0" + n : n;
}

// Helper: format date string to YYYY-MM-DD
function formatDate(dt) {
  if (!dt) return "—";
  const d = new Date(dt);
  return d.toISOString().split("T")[0];
}

export default {
  name: "TeacherReport",
  data() {
    return {
      // If true, build separate private/group tables; otherwise a combined teachers table
      separateTables: false,

      // If true, the feedback table includes only rows with non-empty written feedback
      writtenFeedbackOnly: false,
    };
  },
  methods: {
    /**
     * Triggers generation of the teacher report.
     * Emits:
     *  - [Private, Group, Feedback] if separateTables = true
     *  - [Combined Teachers, Feedback] otherwise
     */
    generateReport() {
      this.$message({ message: "Generating Teacher Report...", type: "success" });
      setTimeout(() => {
        const feedbackTable = this.buildFeedbackTable();

        if (this.separateTables) {
          const privateTable = this.buildPrivateClassesTable();
          const groupTable = this.buildGroupClassesTable();
          this.$emit("report-generated", [privateTable, groupTable, feedbackTable]);
        } else {
          const teachersTable = this.buildTeachersTable();
          this.$emit("report-generated", [teachersTable, feedbackTable]);
        }
      }, 100);
    },

    /* -----------------------------
       UTILITIES FOR CLASS ANALYSIS
       (Derives per-teacher aggregates from combinedData)
    ------------------------------*/
    /**
     * Builds a map of teacherUsername → aggregated class metrics,
     * including counts, tardiness arrays, enrolment rates, etc.
     * @returns {Object} teacherMap keyed by teacher username
     */
    collectClassMetrics() {
      // We’ll pre-group classes by teacher username for efficiency
      const teacherMap = {};

      combinedData.forEach((cls) => {
        const teacher = cls.participants.find((p) => p.isteacher);
        if (!teacher) return;
        const username = teacher.username;
        if (!teacherMap[username]) {
          teacherMap[username] = {
            lessonSummaryCount: 0,
            totalClasses: 0,
            totalAttendedClasses: 0,
            ratingVals: [],
            totalFeedbacks: 0,
            totalAttendedStudents: 0,
            totalTeacherTardiness: [],
            totalStudentTardiness: [],
            studentNoShows: 0,
            enrolRates: [],
            groupSizes: [],
          };
        }
        const entry = teacherMap[username];
        entry.totalClasses++;
        if (!cls.is_cancelled) entry.totalAttendedClasses++;
        if (cls.lesson_topics && !cls.is_cancelled) entry.lessonSummaryCount++;

        // Collect participants
        const students = cls.participants.filter((p) => !p.isteacher);
        const attendedStudents = students.filter((s) => s.attended);

        entry.totalAttendedStudents += attendedStudents.length;
        entry.studentNoShows += students.length - attendedStudents.length;

        // --- enrolment & group size (only for group classes) ---
        if (cls.available_seats > 1) {
          entry.enrolRates.push(students.length / cls.available_seats);
          entry.groupSizes.push(students.filter((s) => !s.is_cancelled).length);
        }

        // Teacher tardiness
        if (teacher.tardiness != null) entry.totalTeacherTardiness.push(teacher.tardiness);

        // Student tardiness + ratings + feedbacks
        attendedStudents.forEach((s) => {
          if (s.tardiness != null) entry.totalStudentTardiness.push(s.tardiness);
          if (s.class_rating != null) {
            entry.ratingVals.push(s.class_rating);
            entry.totalFeedbacks++;
          }
        });
      });

      return teacherMap;
    },

    /** Average of numeric array with safe fallback ("—"). */
    avg(arr) {
      const valid = arr.filter((v) => v != null && !isNaN(v));
      return valid.length ? (valid.reduce((a, b) => a + b, 0) / valid.length).toFixed(2) : "—";
    },

    /** Proportion helper: num/denom → fixed(1), or "—" when denom = 0. */
    rate(num, denom) {
      return denom ? ((num / denom)).toFixed(1) : "—";
    },

    /* -----------------------------
       PRIVATE CLASSES TABLE
       (per-teacher metrics for 1:1 classes)
    ------------------------------*/
    /**
     * Builds the "Private Classes" table (per teacher).
     * Combines users.json fields with derived metrics.
     * @returns {Object} table definition
     */
    buildPrivateClassesTable() {
      const teachers = usersData.teachers || [];
      const classMetrics = this.collectClassMetrics();

      const columns = [
        { label: "Teacher Username", key: "teacher_username" },
        { label: "First Name", key: "first_name" },
        { label: "Last Name", key: "last_name" },
        { tooltip: "Includes cancelled classes.", label: "Total Classes Booked", key: "total_classes_booked" },
        { label: "Total Classes Attended", key: "total_classes_attended" },
        { label: "Cancelled by Teacher", key: "cancelled_by_teacher" },
        { label: "Cancelled by Admin", key: "cancelled_by_admin" },
        { label: "Cancelled by Student", key: "cancelled_by_student" },
        { label: "Teacher No Shows", key: "teacher_no_shows" },
        { label: "Student No Shows", key: "student_no_shows" },
        { tooltip: "Total number of uniques students taught during the report period.", label: "Student Count", key: "student_count" },
        { tooltip: "Number of minutes the teacher is late. Negative values indicate early.", label: "Average Teacher Tardiness", key: "avg_teacher_tardiness" },
        { tooltip: "Number of minutes teacher's students are late. Negative values indicate early.", label: "Average Student Tardiness", key: "avg_student_tardiness" },
        { tooltip: "How many classes for  which teacher leaves a lesson summary. 1 = 100%", label: "Lesson Summary Rate", key: "lesson_summary_rate" },
        { label: "Average Rating", key: "avg_rating" },
        { tooltip: "Rate at which classes students leaves written feedback for. 1 = 100%", label: "Feedback Rate", key: "feedback_rate" },
      ];

      const rows = teachers.map((t) => {
        const metrics = classMetrics[t.username] || {};
        const attendedCount = metrics.totalAttendedClasses || 0;
        const totalCount = metrics.totalClasses || 0;

        return {
          teacher_username: t.username,
          first_name: t.first_name,
          last_name: t.last_name,
          total_classes_booked: t.private_classes_total ?? totalCount ?? "—",
          total_classes_attended: t.private_classes_attended ?? attendedCount ?? "—",
          cancelled_by_teacher: t.private_classes_teacher_cancelled ?? 0,
          cancelled_by_admin: t.private_classes_admin_cancelled ?? 0,
          cancelled_by_student: t.private_classes_student_cancelled ?? 0,
          teacher_no_shows:
            (t.private_classes_total ?? totalCount ?? 0) -
            (t.private_classes_attended ?? attendedCount ?? 0) -
            (t.private_classes_cancelled ?? 0),
          student_no_shows: metrics.studentNoShows ?? "—",
          student_count: t.student_count ?? "—",
          avg_teacher_tardiness: this.avg(metrics.totalTeacherTardiness),
          avg_student_tardiness: this.avg(metrics.totalStudentTardiness),
          lesson_summary_rate: this.rate(metrics.lessonSummaryCount, attendedCount),
          avg_rating: this.avg(metrics.ratingVals),
          feedback_rate: this.rate(metrics.totalFeedbacks, metrics.totalAttendedStudents),
        };
      });

      return {
        title: "Private Classes",
        columns,
        rows,
        format: { table: { scrollable: true, maxHeight: 800 } },
      };
    },

    /* -----------------------------
       GROUP CLASSES TABLE
       (per-teacher metrics for group classes)
    ------------------------------*/
    /**
     * Builds the "Group Classes" table (per teacher).
     * Includes enrolment rates and group size metrics.
     * @returns {Object} table definition
     */
    buildGroupClassesTable() {
      const teachers = usersData.teachers || [];
      const classMetrics = this.collectClassMetrics();

      const columns = [
        { label: "Teacher Username", key: "teacher_username" },
        { label: "First Name", key: "first_name" },
        { label: "Last Name", key: "last_name" },
        { tooltip: "Includes cancelled classes.", label: "Total Classes Booked", key: "total_classes_booked" },
        { label: "Total Classes Attended", key: "total_classes_attended" },
        { label: "Cancelled by Teacher", key: "cancelled_by_teacher" },
        { label: "Cancelled by Admin", key: "cancelled_by_admin" },
        { label: "Enrolment Rate", key: "enrolment_rate" },
        { label: "Teacher No Shows", key: "teacher_no_shows" },
        { label: "Student No Shows", key: "student_no_shows" },
        { label: "Average Group Size", key: "avg_group_size" },
        { tooltip: "Total number of uniques students taught during the report period.", label: "Student Count", key: "student_count" },
        { tooltip: "Number of minutes the teacher is late. Negative values indicate early.", label: "Average Teacher Tardiness", key: "avg_teacher_tardiness" },
        { tooltip: "Number of minutes teacher's students are late. Negative values indicate early.", label: "Average Student Tardiness", key: "avg_student_tardiness" },
        { tooltip: "How many classes for  which teacher leaves a lesson summary. 1 = 100%", label: "Lesson Summary Rate", key: "lesson_summary_rate" },
        { label: "Average Rating", key: "avg_rating" },
        { tooltip: "Rate at which classes students leaves written feedback for. 1 = 100%", label: "Feedback Rate", key: "feedback_rate" },
      ];

      const rows = teachers.map((t) => {
        const metrics = classMetrics[t.username] || {};
        const attendedCount = metrics.totalAttendedClasses || 0;
        const totalCount = metrics.totalClasses || 0;

        return {
          teacher_username: t.username,
          first_name: t.first_name,
          last_name: t.last_name,
          total_classes_booked: t.group_classes_total ?? totalCount ?? "—",
          total_classes_attended: t.group_classes_attended ?? attendedCount ?? "—",
          cancelled_by_teacher: t.group_classes_teacher_cancelled ?? 0,
          cancelled_by_admin: t.group_classes_admin_cancelled ?? 0,
          enrolment_rate: this.avg(metrics.enrolRates),
          teacher_no_shows:
            (t.group_classes_total ?? totalCount ?? 0) -
            (t.group_classes_attended ?? attendedCount ?? 0) -
            (t.group_classes_cancelled ?? 0),
          student_no_shows: metrics.studentNoShows ?? "—",
          avg_group_size: this.avg(metrics.groupSizes),
          student_count: t.student_count ?? "—",
          avg_teacher_tardiness: this.avg(metrics.totalTeacherTardiness),
          avg_student_tardiness: this.avg(metrics.totalStudentTardiness),
          lesson_summary_rate: this.rate(metrics.lessonSummaryCount, attendedCount),
          avg_rating: this.avg(metrics.ratingVals),
          feedback_rate: this.rate(metrics.totalFeedbacks, metrics.totalAttendedStudents),
        };
      });

      return {
        title: "Group Classes",
        columns,
        rows,
        format: { table: { scrollable: true, maxHeight: 800 } },
      };
    },

    /* -----------------------------
       COMBINED TEACHERS TABLE
       (aggregates across private + group)
    ------------------------------*/
    /**
     * Builds the combined "Teachers" table (per teacher).
     * Uses totals across all class types plus derived metrics.
     * @returns {Object} table definition
     */
    buildTeachersTable() {
      const teachers = usersData.teachers || [];
      const classMetrics = this.collectClassMetrics();

      const columns = [
        { label: "Teacher Username", key: "teacher_username" },
        { label: "First Name", key: "first_name" },
        { label: "Last Name", key: "last_name" },
        { tooltip: "Includes cancelled classes.", label: "Total Classes Booked", key: "total_classes_booked" },
        { label: "Total Classes Attended", key: "total_classes_attended" },
        { label: "Cancelled by Teacher", key: "cancelled_by_teacher" },
        { label: "Cancelled by Admin", key: "cancelled_by_admin" },
        { label: "Cancelled by Student", key: "cancelled_by_student" },
        { label: "Group Class Enrolment Rate", key: "enrolment_rate" },
        { label: "Teacher No Shows", key: "teacher_no_shows" },
        { label: "Student No Shows", key: "student_no_shows" },
        { label: "Average Group Size", key: "avg_group_size" },
        {tooltip: "Total number of uniques students taught during the report period.", label: "Student Count", key: "student_count" },
        { tooltip: "Number of minutes the teacher is late. Negative values indicate early.", label: "Average Teacher Tardiness", key: "avg_teacher_tardiness" },
        { tooltip: "Number of minutes teacher's students are late. Negative values indicate early.", label: "Average Student Tardiness", key: "avg_student_tardiness" },
        { tooltip: "How many classes for  which teacher leaves a lesson summary. 1 = 100%", label: "Lesson Summary Rate", key: "lesson_summary_rate" },
        { label: "Average Rating", key: "avg_rating" },
        { tooltip: "Rate at which classes students leaves written feedback for. 1 = 100%", label: "Feedback Rate", key: "feedback_rate" },
      ];

      const rows = teachers.map((t) => {
        const metrics = classMetrics[t.username] || {};
        const attendedCount = metrics.totalAttendedClasses || 0;
        const totalCount = metrics.totalClasses || 0;

        return {
          teacher_username: t.username,
          first_name: t.first_name,
          last_name: t.last_name,
          total_classes_booked: t.total_classes ?? totalCount ?? "—",
          total_classes_attended: t.total_attended ?? attendedCount ?? "—",
          cancelled_by_teacher: t.total_teacher_cancelled ?? 0,
          cancelled_by_admin: t.total_admin_cancelled ?? 0,
          cancelled_by_student: t.private_classes_student_cancelled ?? 0,
          enrolment_rate: this.avg(metrics.enrolRates),
          teacher_no_shows:
            (t.total_classes ?? totalCount ?? 0) -
            (t.total_attended ?? attendedCount ?? 0) -
            (t.total_cancelled ?? 0),
          student_no_shows: metrics.studentNoShows ?? "—",
          avg_group_size: this.avg(metrics.groupSizes),
          student_count: t.student_count ?? "—",
          avg_teacher_tardiness: this.avg(metrics.totalTeacherTardiness),
          avg_student_tardiness: this.avg(metrics.totalStudentTardiness),
          lesson_summary_rate: this.rate(metrics.lessonSummaryCount, attendedCount),
          avg_rating: this.avg(metrics.ratingVals),
          feedback_rate: this.rate(metrics.totalFeedbacks, metrics.totalAttendedStudents),
        };
      });

      return {
        title: "Teachers",
        columns,
        rows,
        format: { table: { scrollable: true, maxHeight: 800 } },
      };
    },

    /* -----------------------------
       STUDENT FEEDBACK TABLE
       (optionally only written feedback)
    ------------------------------*/
    /**
     * Builds the "Student Feedback" table.
     * Respects the "writtenFeedbackOnly" toggle to include only
     * entries with non-empty class_review text when enabled.
     * @returns {Object} table definition
     */
    buildFeedbackTable() {
      const columns = [
        { label: "Teacher Username", key: "teacher_username" },
        { label: "Student Username", key: "student_username" },
        { label: "Class Date", key: "class_date" },
        { label: "Class Slug", key: "class_slug" },
        { label: "Feedback", key: "feedback" },
        { label: "Rating", key: "rating" },
      ];

      const rows = combinedData.flatMap((cls) => {
        const teacher = cls.participants.find((p) => p.isteacher);
        const students = cls.participants.filter((p) => !p.isteacher);

        return students
            .filter((s) => {
            // Always require at least a rating or review
            if (!(s.class_review || s.class_rating != null)) return false;

            // If "written feedback only" is ticked, keep only those with non-empty text
            if (this.writtenFeedbackOnly && !s.class_review?.trim()) return false;

            return true;
            })
            .map((s) => ({
            teacher_username: teacher ? teacher.username : "—",
            student_username: s.username,
            class_date: formatDate(cls.scheduled_start),
            class_slug: cls.slug || "—",
            feedback: s.class_review?.trim() || "—",
            rating: s.class_rating != null ? s.class_rating : "—",
            }));
        });

      return {
        title: "Student Feedback",
        columns,
        rows,
        format: { table: { scrollable: true, maxHeight: 800 } },
      };
    },
  },
};
</script>

