<template>
  <div class="classlist-settings">
    <h3 class="title">Class List Report</h3>

    <!-- ======= FORM CONTROLS ======= -->
    <el-form class="settings-form">
      <!-- Grouping Mode -->
      <el-form-item>
        <div class="label-above">
          <span>Group By</span>
          <el-radio-group v-model="groupMode" class="vertical-radios">
            <el-radio label="class">Class</el-radio>
            <el-radio label="student">Student</el-radio>
          </el-radio-group>
        </div>
      </el-form-item>

      <!-- Report Options -->
      <el-form-item>
        <div class="label-above">
          <span>Report Options</span>
          <el-checkbox v-model="includeCancelled" style="margin-bottom:5px;">
            Include cancelled classes
          </el-checkbox>
          <el-checkbox v-model="showAdvanced">Advanced</el-checkbox>
        </div>
      </el-form-item>

      <!-- Generate Button -->
      <el-form-item>
        <el-button type="primary" size="medium" @click="generateReport">
          Generate Report
        </el-button>
      </el-form-item>
    </el-form>
  </div>
</template>

<script>
/**
 * ===========================================================
 * Component: ClassListReport.vue
 * Description:
 *   Configuration panel to build class lists grouped by class
 *   or by student. Supports toggling inclusion of cancelled
 *   classes and optional advanced metadata columns.
 *
 * Data Flow:
 *   - Reads from static combined.json (class sessions + participants).
 *   - Builds one or more table objects (columns, rows, format).
 *   - Emits "report-generated" with the assembled tables to parent.
 * ===========================================================
 */

import combinedData from "@/data/combined.json";

/* ---------------- Helper functions (formatting & stats) ---------------- */

// Pad single-digit numbers with a leading zero (for HH/MM/SS)
function pad(n) {
  return n < 10 ? '0' + n : n;
}

// Convert date string to YYYY-MM-DD (ISO date-only)
function formatDate(dt) {
  if (!dt) return "—";
  const d = new Date(dt);
  return d.toISOString().split("T")[0];
}

// Convert date string to HH:MM (24h)
function formatTime(dt) {
  if (!dt) return "—";
  const d = new Date(dt);
  return pad(d.getHours()) + ":" + pad(d.getMinutes());
}

// Format minutes into HH:MM
function formatDurationMins(minutes) {
  if (!minutes && minutes !== 0) return "—";
  const hrs = Math.floor(minutes / 60);
  const mins = Math.round(minutes % 60);
  return `${pad(hrs)}:${pad(mins)}`;
}

// Format minutes into HH:MM:SS (by converting to seconds)
function formatDurationSec(minutes) {
  if (!minutes && minutes !== 0) return "—";
  const totalSec = Math.round(minutes * 60);
  const hrs = Math.floor(totalSec / 3600);
  const mins = Math.floor((totalSec % 3600) / 60);
  const secs = totalSec % 60;
  return `${pad(hrs)}:${pad(mins)}:${pad(secs)}`;
}

// Average of numeric array (safe fallback to "—")
function average(arr) {
  const nums = arr.filter(v => v != null && !isNaN(v));
  return nums.length ? (nums.reduce((a, b) => a + b, 0) / nums.length).toFixed(2) : "—";
}

/**
 * Optional advanced metadata columns shown when "Advanced" is enabled.
 * These reflect platform-level flags and identifiers for diagnostics.
 */
const ADVANCED_COLUMNS = [
  { tooltip: "Unique class identifier", label: "Class Slug", key: "class_slug" },
  { tooltip: "Was this class set to demo room mode? (Online School platform setting)", label: "Demo Room", key: "is_demo" },
  { tooltip: "Was this class set to be recorded?", label: "Recorded", key: "is_recorded_class" },
  { tooltip: "Was this class set to free class mode? (Online School platform setting)", label: "Free Class", key: "is_free_class" },
  { tooltip: "Was homework set for this class?", label: "Homework", key: "homework" },
  { tooltip: "Was this class set to wb only mode?", label: "Whiteboard Only", key: "is_whiteboard_only" },
  { tooltip: "Was this class set to large group / webinar moder?", label: "Webinar Mode", key: "webinar_mode" },
  { tooltip: "Reminder emails are sent to Online School platform users, 2 hours before class", label: "Reminder Sent", key: "reminder_sent" }
];

export default {
  name: "ClassListReport",
  data() {
    return {
      groupMode: "class",       // "class" or "student"
      showAdvanced: false,      // toggle advanced metadata fields
      includeCancelled: true,   // include cancelled sessions in results
    };
  },
  methods: {
    /**
     * Triggers generation of the report based on current options.
     * - Optionally filters out cancelled classes.
     * - Emits one or more table objects depending on grouping.
     */
    generateReport() {
      this.$message({ message: "Generating Class List Report...", type: "success" });
      setTimeout(() => {
        let data = combinedData;
        if (!this.includeCancelled) {
          data = data.filter((c) => !c.is_cancelled);
        }
        if (this.groupMode === "class") {
          const priv = data.filter(c => c.available_seats === 1);
          const group = data.filter(c => c.available_seats > 1);
          this.$emit("report-generated", [
            this.buildPrivateClassTable(priv),
            this.buildGroupClassTable(group),
          ]);
        } else {
          this.$emit("report-generated", [this.buildStudentClassTable(data)]);
        }
      }, 50);
    },

    /**
     * Builds table for 1:1 (private) classes. Optionally injects
     * advanced columns when "Advanced" is enabled.
     * @param {Array} classes - Array of class session objects
     * @returns {Object} Table definition (title, columns, rows, format)
     */
    buildPrivateClassTable(classes) {
      // Dynamic columns: remove 'Status' if exclude cancelled
      const baseColumns = [
        { label: "Date", key: "date" },
        { label: "Time", key: "time" },
        { label: "Scheduled Duration", key: "scheduled_duration" },
        { label: "Actual Duration", key: "actual_duration" },
        this.includeCancelled ? { tooltip: "Completed means not cancelled.", label: "Status", key: "status" } : null,
        { label: "Company", key: "company" },
        { label: "Subject", key: "subject" },
        { label: "Level", key: "level" },
        { label: "Description", key: "description" },
        { label: "Teacher Username", key: "teacher_username" },
        { label: "Teacher Name", key: "teacher_name" },
        { label: "Teacher Attended", key: "teacher_attended" },
        { tooltip: "Number of minutes user is late for class (negative values mean they are early)", label: "Teacher Tardiness", key: "teacher_tardiness" },
        { label: "Teacher Summary", key: "teacher_summary" },
        { label: "Student Username", key: "student_username" },
        { label: "Student Name", key: "student_name" },
        { label: "Student Attended", key: "student_attended" },
        { tooltip: "Number of minutes user is late for class (negative values mean they are early)", label: "Student Tardiness", key: "student_tardiness" },
        { label: "Class Feedback", key: "class_feedback" },
        { tooltip: "Students rate classes out of 5 stars.", label: "Class Rating", key: "class_rating" },
        { tooltip: "Unique course identifier. If blank, class is not part of a course.", label: "Course ID", key: "course_id" }
      ].filter(Boolean);

      const columns = this.showAdvanced
        ? [
            ...baseColumns.slice(0, 9),
            ...ADVANCED_COLUMNS.filter(c => c.key === "class_slug"),
            ...baseColumns.slice(9, -1),
            ...ADVANCED_COLUMNS.filter(c => c.key !== "class_slug"),
            baseColumns[baseColumns.length - 1],
          ]
        : baseColumns;

      const rows = classes.map(cls => {
        const teacher = cls.participants.find(p => p.isteacher) || {};
        const student = cls.participants.find(p => !p.isteacher) || {};
        const advFields = {
          class_slug: cls.slug || "—",
          is_demo: !!cls.is_demo,
          is_recorded_class: !!cls.is_recorded_class,
          is_free_class: !!cls.is_free_class,
          homework: !!cls.homework,
          is_whiteboard_only: !!cls.is_whiteboard_only,
          webinar_mode: !!cls.webinar_mode,
          reminder_sent: !!cls.reminder_sent,
        };
        return {
          date: formatDate(cls.scheduled_start),
          time: formatTime(cls.scheduled_start),
          scheduled_duration: formatDurationMins(cls.scheduled_duration),
          actual_duration: formatDurationSec(cls.actual_duration),
          status: cls.is_cancelled ? "cancelled" : "completed",
          company: cls.company || "—",
          subject: cls.class_lang || "—",
          level: cls.lang_level || "—",
          description: cls.class_notes || "—",
          teacher_username: teacher.username || "—",
          teacher_name: [teacher.first_name, teacher.last_name].filter(Boolean).join(' ') || "—",
          teacher_attended: teacher.attended_time || "—",
          teacher_tardiness: teacher.tardiness != null ? teacher.tardiness.toFixed(2) : "—",
          teacher_summary: cls.lesson_topics || "—",
          student_username: student.username || "—",
          student_name: [student.first_name, student.last_name].filter(Boolean).join(' ') || "—",
          student_attended: student.attended_time || "—",
          student_tardiness: student.tardiness != null ? student.tardiness.toFixed(2) : "—",
          class_feedback: student.class_review || "—",
          class_rating: student.class_rating != null ? student.class_rating : "—",
          course_id: cls.course_id,
          ...advFields
        };
      });
      return {
        title: "Private Classes List",
        columns,
        rows,
        format: { table: { scrollable: true, maxHeight: 800 } }
      };
    },

    /**
     * Builds table for group classes, including enrolment and
     * attendance summaries per class. Advanced columns optional.
     * @param {Array} classes
     * @returns {Object} Table definition
     */
    buildGroupClassTable(classes) {
      const baseColumns = [
        { label: "Date", key: "date" },
        { label: "Time", key: "time" },
        { label: "Scheduled Duration", key: "scheduled_duration" },
        { label: "Actual Duration", key: "actual_duration" },
        this.includeCancelled ? { label: "Status", key: "status" } : null,
        { label: "Company", key: "company" },
        { label: "Subject", key: "subject" },
        { label: "Level", key: "level" },
        { label: "Description", key: "description" },
        { label: "Teacher Username", key: "teacher_username" },
        { label: "Teacher Name", key: "teacher_name" },
        { label: "Teacher Attended", key: "teacher_attended" },
        { tooltip: "Number of minutes user is late for class (negative values mean they are early)", label: "Teacher Tardiness", key: "teacher_tardiness" },
        { label: "Teacher Summary", key: "teacher_summary" },
        { tooltip: "Total available enrolment spaces.", label: "Seats", key: "seats" },
        { label: "Students Enrolled", key: "students_enrolled" },
        { label: "Students Attended", key: "students_attended" },
        { label: "Student Usernames", key: "student_usernames" },
        { label: "Class Feedback", key: "class_feedback" },
        { tooltip: "Average of student ratings. Students rate classes out of 5 stars.", label: "Class Rating", key: "class_rating" },
        { tooltip: "Unique course identifier. If blank, class is not part of a course.", label: "Course ID", key: "course_id" }
      ].filter(Boolean);

      const columns = this.showAdvanced
        ? [
            ...baseColumns.slice(0, 9),
            ...ADVANCED_COLUMNS.filter(c => c.key === "class_slug"),
            ...baseColumns.slice(9, -1),
            ...ADVANCED_COLUMNS.filter(c => c.key !== "class_slug"),
            baseColumns[baseColumns.length - 1]
          ]
        : baseColumns;

      const rows = classes.map(cls => {
        const teacher = cls.participants.find(p => p.isteacher) || {};
        const students = cls.participants.filter(p => !p.isteacher);
        const enrolled = students.filter(s => !s.is_cancelled);
        const attendedCount = students.filter(s => s.attended).length;
        const feedbacks = students.map(s => s.class_review).filter(Boolean).join(", ");
        const ratings = students.map(s => s.class_rating).filter(r => r != null);
        const advFields = {
          class_slug: cls.slug || "—",
          is_demo: !!cls.is_demo,
          is_recorded_class: !!cls.is_recorded_class,
          is_free_class: !!cls.is_free_class,
          homework: !!cls.homework,
          is_whiteboard_only: !!cls.is_whiteboard_only,
          webinar_mode: !!cls.webinar_mode,
          reminder_sent: !!cls.reminder_sent,
        };
        return {
          date: formatDate(cls.scheduled_start),
          time: formatTime(cls.scheduled_start),
          scheduled_duration: formatDurationMins(cls.scheduled_duration),
          actual_duration: formatDurationSec(cls.actual_duration),
          status: cls.is_cancelled ? "cancelled" : "completed",
          company: cls.company || "—",
          subject: cls.class_lang || "—",
          level: cls.lang_level || "—",
          description: cls.class_notes || "—",
          teacher_username: teacher.username || "—",
          teacher_name: [teacher.first_name, teacher.last_name].filter(Boolean).join(' ') || "—",
          teacher_attended: teacher.attended_time || "—",
          teacher_tardiness: teacher.tardiness != null ? teacher.tardiness.toFixed(2) : "—",
          teacher_summary: cls.lesson_topics || "—",
          seats: cls.available_seats ?? "—",
          students_enrolled: enrolled.length,
          students_attended: attendedCount,
          student_usernames: students.map(s => s.username).filter(Boolean).join(", "),
          class_feedback: feedbacks || "—",
          class_rating: ratings.length ? average(ratings) : "—",
          course_id: cls.course_id,
          ...advFields
        };
      });
      return {
        title: "Group Classes List",
        columns,
        rows,
        format: { table: { scrollable: true, maxHeight: 800 } }
      };
    },

    /**
     * Builds table grouped by student (one row per student-class pair).
     * @param {Array} classes
     * @returns {Object} Table definition
     */
    buildStudentClassTable(classes) {
      const baseColumns = [
        { label: "Date", key: "date" },
        { label: "Time", key: "time" },
        { label: "Scheduled Duration", key: "scheduled_duration" },
        { label: "Actual Duration", key: "actual_duration" },
        this.includeCancelled ? { label: "Status", key: "status" } : null,
        { label: "Company", key: "company" },
        { label: "Subject", key: "subject" },
        { label: "Level", key: "level" },
        { label: "Description", key: "description" },
        { label: "Group Class", key: "group_class" },
        { label: "Student Username", key: "student_username" },
        { label: "Student Name", key: "student_name" },
        { label: "Student Attended", key: "student_attended" },
        { tooltip: "Number of minutes user is late for class (negative values mean they are early)", label: "Student Tardiness", key: "student_tardiness" },
        { label: "Class Feedback", key: "class_feedback" },
        { tooltip: "Students rate classes out of 5 stars.", label: "Class Rating", key: "class_rating" },
        { label: "Teacher Username", key: "teacher_username" },
        { label: "Teacher Name", key: "teacher_name" },
        { label: "Teacher Attended", key: "teacher_attended" },
        { tooltip: "Number of minutes user is late for class (negative values mean they are early)", label: "Teacher Tardiness", key: "teacher_tardiness" },
        { label: "Teacher Summary", key: "teacher_summary" },
        { tooltip: "Course ID", label: "Course ID", key: "course_id" }
      ].filter(Boolean);

      const columns = this.showAdvanced
        ? [
            ...baseColumns.slice(0, 9),
            ...ADVANCED_COLUMNS.filter(c => c.key === "class_slug"),
            ...baseColumns.slice(9, -1),
            ...ADVANCED_COLUMNS.filter(c => c.key !== "class_slug"),
            baseColumns[baseColumns.length - 1]
          ]
        : baseColumns;

      const rows = classes.flatMap(cls => {
        const teacher = cls.participants.find(p => p.isteacher) || {};
        const students = cls.participants.filter(p => !p.isteacher);
        const isGroup = cls.available_seats > 1;
        const advFields = {
          class_slug: cls.slug || "—",
          is_demo: !!cls.is_demo,
          is_recorded_class: !!cls.is_recorded_class,
          is_free_class: !!cls.is_free_class,
          homework: !!cls.homework,
          is_whiteboard_only: !!cls.is_whiteboard_only,
          webinar_mode: !!cls.webinar_mode,
          reminder_sent: !!cls.reminder_sent,
        };
        return students.map(student => ({
          date: formatDate(cls.scheduled_start),
          time: formatTime(cls.scheduled_start),
          scheduled_duration: formatDurationMins(cls.scheduled_duration),
          actual_duration: formatDurationSec(cls.actual_duration),
          status: cls.is_cancelled ? "cancelled" : "completed",
          company: cls.company || "—",
          subject: cls.class_lang || "—",
          level: cls.lang_level || "—",
          description: cls.class_notes || "—",
          group_class: isGroup,
          student_username: student.username || "—",
          student_name: [student.first_name, student.last_name].filter(Boolean).join(' ') || "—",
          student_attended: student.attended_time || "—",
          student_tardiness: student.tardiness != null ? student.tardiness.toFixed(2) : "—",
          class_feedback: student.class_review || "—",
          class_rating: student.class_rating != null ? student.class_rating : "—",
          teacher_username: teacher.username || "—",
          teacher_name: [teacher.first_name, teacher.last_name].filter(Boolean).join(' ') || "—",
          teacher_attended: teacher.attended_time || "—",
          teacher_tardiness: teacher.tardiness != null ? teacher.tardiness.toFixed(2) : "—",
          teacher_summary: cls.lesson_topics || "—",
          course_id: cls.course_id,
          ...advFields
        }));
      });
      return {
        title: "Student Class List",
        columns,
        rows,
        format: { table: { scrollable: true, maxHeight: 800 } }
      };
    }
  }
};
</script>

