<!--
  ==========================================================
  Component: StudentReport.vue
  Description:
    Configuration panel and report generator for student-level reporting.
    Allows the user to select between Count and Rate modes, optionally
    separate private and group class tables, and filter by student selection
    (All Students, Company, or Custom List).

  Responsibilities:
    - Collect user configuration for report generation.
    - Filter static class and user data according to student selection.
    - Build structured report tables (one or two) depending on selected mode.
    - Emit formatted tables to the parent (App.vue) for rendering.

  Data Sources:
    - combined.json → per-class aggregated data
    - users.json → aggregated statistics per user
    - globalSettings.js → shared reactive configuration (e.g. cancellation window)

  Notes:
    - The “Company” selector populates dynamically from combined.json.
    - “Custom List” allows adding/removing usernames via tags.
    - This prototype uses static data; future versions will fetch dynamically.
  ==========================================================
-->

<template>
  <div class="student-report-settings">
    <h3 class="title">Student Report</h3>

    <el-form class="settings-form">
      <!-- ======= SEPARATE TABLES ======= -->
      <el-form-item>
        <div class="label-above-checkbox">
          <span>Separate Group and Private Classes</span>
          <el-checkbox v-model="separateTables" size="small"></el-checkbox>
        </div>
      </el-form-item>

      <!-- ======= INTERVAL UNIT SELECT ======= -->
        <el-form-item>
            <div class="label-above">
                <span>Interval Units</span>
                <el-select v-model="intervalUnit" placeholder="Select Unit" size="small">
                <el-option label="Hours" value="hours" />
                <el-option label="Minutes" value="minutes" />
                <el-option label="Days" value="days" />
                </el-select>
            </div>
        </el-form-item>

      <!-- ======= DISPLAY MODE ======= -->
      <el-form-item>
        <div class="label-above">
          <span>Display Mode</span>
          <el-radio-group v-model="displayMode">
            <el-radio label="count">Count</el-radio>
            <el-radio label="rate">Rate</el-radio>
          </el-radio-group>
        </div>
      </el-form-item>

      <!-- ======= STUDENT SELECTION ======= -->
      <el-form-item>
        <div class="label-above">
          <span>Student Selection</span>
          <el-radio-group v-model="studentSelection">
            <el-radio label="all">All Students</el-radio>
            <el-radio label="company">Company</el-radio>
            <el-radio label="custom">Custom List</el-radio>
          </el-radio-group>
        </div>
      </el-form-item>

      <!-- ======= COMPANY SELECT ======= -->
      <el-form-item v-if="studentSelection === 'company'">
        <div class="label-above">
          <span>Company</span>
          <el-select v-model="selectedCompany" placeholder="Select company" size="small">
            <el-option label="All" value="All" />
            <el-option
              v-for="company in companyList"
              :key="company"
              :label="company"
              :value="company"
            />
          </el-select>
        </div>
      </el-form-item>

      <!-- ======= CUSTOM LIST ======= -->
      <el-form-item v-if="studentSelection === 'custom'">
        <div class="label-above">
          <span>Add Students</span>
          <div class="custom-list-container">
            <el-input
              v-model="customUserInput"
              placeholder="Enter usernames (comma-separated)"
              size="small"
              class="input"
            />
            <el-button type="primary" size="small" @click="addUsernames">Add</el-button>
          </div>
          <div class="tag-container">
            <el-tag
              v-for="(user, index) in customUsernames"
              :key="index"
              closable
              @close="removeUsername(index)"
            >
              {{ user }}
            </el-tag>
          </div>
        </div>
      </el-form-item>

      <!-- ======= GENERATE BUTTON ======= -->
      <el-form-item>
        <el-button type="primary" size="medium" @click="generateReport">
          Generate Report
        </el-button>
      </el-form-item>
    </el-form>
  </div>
</template>


<script>
import combinedData from "@/data/combined.json";
import usersData from "@/data/users.json";
import { globalSettings } from "@/store/globalSettings";

export default {
  name: "StudentReport",

  data() {
    return {
      separateTables: false,
      displayMode: "count", // 'count' or 'rate'
      studentSelection: "all", // 'all', 'company', 'custom'
      selectedCompany: "All",
      companyList: [],
      customUserInput: "",
      customUsernames: [],
      intervalUnit: "hours",
    };
  },

  mounted() {
    this.companyList = this.getCompanies();
  },

  methods: {
    /** Extracts unique company names from combinedData participants. */
    getCompanies() {
      const companies = new Set();
      combinedData.forEach((cls) => {
        cls.participants
          .filter((p) => !p.isteacher && p.company)
          .forEach((s) => companies.add(s.company));
      });
      return Array.from(companies).sort();
    },

    /** Adds usernames from the input box as tags. */
    addUsernames() {
      if (!this.customUserInput.trim()) return;
      const names = this.customUserInput
        .split(",")
        .map((n) => n.trim())
        .filter((n) => n && !this.customUsernames.includes(n));
      this.customUsernames.push(...names);
      this.customUserInput = "";
    },

    /** Removes a username tag by index. */
    removeUsername(index) {
      this.customUsernames.splice(index, 1);
    },

    /** Average helper. */
    avg(arr) {
      const valid = arr.filter((v) => v != null && !isNaN(v));
      return valid.length
        ? valid.reduce((a, b) => a + b, 0) / valid.length
        : null;
    },

    /** Round helper. */
    round(val) {
      return val != null && !isNaN(val) ? Number(val.toFixed(2)) : "–";
    },

    /** Safe rate helper. */
    rate(num, denom) {
      return denom ? (num / denom).toFixed(2) : "–";
    },

    /** Converts a time value into the selected display unit. */
    convertInterval(value) {
    if (!value) return 0;
    if (this.intervalUnit === "minutes") return value * 60;
    if (this.intervalUnit === "days") return value / 24;
    return value; // hours
    },

    /** Filters student list based on user selection. */
    getSelectedStudents() {
      let allStudents = usersData.students || [];

      if (this.studentSelection === "all") {
        return allStudents;
      }

      if (this.studentSelection === "company") {
        if (this.selectedCompany === "All") return allStudents;
        return allStudents.filter((s) => s.company === this.selectedCompany);
      }

      if (this.studentSelection === "custom") {
        return allStudents.filter((s) =>
          this.customUsernames.includes(s.username)
        );
      }

      return allStudents;
    },

    /**
     * Builds table for Count mode.
     * @param {Array} students - array of student objects
     * @param {String} classType - 'private', 'group', or 'all'
     */
    buildCountTable(students, classType = "all") {
      const cancellationWindow = globalSettings.cancellationWindow * 60;

      const columns = [
        { label: "Student", key: "student" },
        { label: "Company", key: "company" },
        ...(classType === "all"
          ? [
              { label: "Total Classes", key: "total_classes" },
              { label: "Total Group Classes", key: "total_group" },
              { label: "Total Private Classes", key: "total_private" },
            ]
          : [{ label: "Total Classes", key: "total_classes" }]),
        { label: "Attended", key: "attended" },
        { label: "No Show", key: "no_show" },
        { label: "Cancelled", key: "cancelled" },
        { label: "Cancelled by Teacher", key: "cancelled_by_teacher" },
        { label: "Cancelled by Admin", key: "cancelled_by_admin" },
        { tooltip: "Cancelled by the student", label: "Self-Cancellation", key: "cancelled_by_student" },
        { tooltip: `Classes cancelled by the student in less than ${globalSettings.cancellationWindow}h)`, label: `Late Cancellations (<${globalSettings.cancellationWindow}h)`, key: "late_cancellations" },
        { tooltip: "The average time between cancellation and the class start time", label: "Average Cancellation Interval", key: "avg_cancellation_interval" },
        { tooltip: "Number of minutes the student is late. Negative values indicate early.", label: "Average Tardiness", key: "avg_tardiness" },
        { label: "Average Rating", key: "avg_rating" },
        { tooltip: "How many classes this student leaves written feedback for. 1 = 100%", label: "Feedback Rate", key: "feedback_rate" },
        { tooltip: "The average time between enrolment and class start.", label: "Average Enrolment Interval", key: "avg_enrolment_interval" },
        { tooltip: "The average time between classes.", label: "Average Class Interval", key: "avg_class_interval" },
      ];

      const rows = students.map((s) => ({
        student: s.username,
        company: s.company || "–",
        total_classes: s.total_classes,
        total_group: s.group_classes_total,
        total_private: s.private_classes_total,
        attended: s.total_attended,
        no_show: (s.total_classes - s.total_attended - s.total_cancelled) || 0,
        cancelled: s.total_cancelled,
        cancelled_by_teacher: s.total_teacher_cancelled,
        cancelled_by_admin:
          s.total_cancelled -
          (s.total_student_cancelled + s.total_teacher_cancelled),
        cancelled_by_student: s.total_student_cancelled,
        late_cancellations:
          s.total_student_cancelled < cancellationWindow ? 1 : 0,
        avg_cancellation_interval: this.round(this.convertInterval(s.average_cancellation_interval)),
        avg_tardiness: this.round(s.average_tardiness),
        avg_rating: this.round(s.average_rating),
        feedback_rate: this.rate(s.feedback_count || 0, s.total_attended || 0),
        avg_enrolment_interval: this.round(this.convertInterval(s.enrolment_interval)),
        avg_class_interval: this.round(this.convertInterval(s.class_interval)),
      }));

      return {
        title:
          classType === "private"
            ? "Student Report - Private Classes (Count)"
            : classType === "group"
            ? "Student Report - Group Classes (Count)"
            : "Student Report (Count)",
        columns,
        rows,
        format: { table: { scrollable: true, maxHeight: 800 } },
      };
    },

    /**
     * Builds table for Rate mode.
     * @param {Array} students - array of student objects
     * @param {String} classType - 'private', 'group', or 'all'
     */
    buildRateTable(students, classType = "all") {
      const columns = [
        { label: "Student", key: "student" },
        { label: "Company", key: "company" },
        ...(classType === "all"
          ? [
              { label: "Total Classes", key: "total_classes" },
              { label: "Total Group Classes", key: "total_group" },
              { label: "Total Private Classes", key: "total_private" },
            ]
          : [{ label: "Total Classes", key: "total_classes" }]),
        { tooltip: "1 = 100%", label: "Attendance Rate", key: "attendance_rate" },
        { label: "No Show Rate", key: "no_show_rate" },
        { tooltip: "1 = 100%", label: "Cancellation Rate", key: "cancellation_rate" },
        { label: "Average Tardiness", key: "avg_tardiness" },
        { label: "Average Rating", key: "avg_rating" },
        { tooltip: "How many classes this student leaves written feedback for. 1 = 100%", label: "Feedback Rate", key: "feedback_rate" },
        { tooltip: "The average time between enrolment and class start.", label: "Average Enrolment Interval", key: "avg_enrolment_interval" },
        { tooltip: "The average time between classes.", label: "Average Class Interval", key: "avg_class_interval" },
      ];

      const rows = students.map((s) => {
        const attended = s.total_attended || 0;
        const cancelled = s.total_cancelled || 0;
        const total = s.total_classes || 0;
        const validTotal = total - cancelled;

        return {
          student: s.username,
          company: s.company || "–",
          total_classes: total,
          total_group: s.group_classes_total,
          total_private: s.private_classes_total,
          attendance_rate: this.rate(attended, validTotal),
          no_show_rate: this.rate(validTotal - attended, validTotal),
          cancellation_rate: this.rate(cancelled, total),
          avg_tardiness: this.round(s.average_tardiness),
          avg_rating: this.round(s.average_rating),
          feedback_rate: this.rate(s.feedback_count || 0, attended || 0),
          avg_enrolment_interval: this.round(this.convertInterval(s.enrolment_interval)),
          avg_class_interval: this.round(this.convertInterval(s.class_interval)),
        };
      });

      return {
        title:
          classType === "private"
            ? "Student Report - Private Classes (Rate)"
            : classType === "group"
            ? "Student Report - Group Classes (Rate)"
            : "Student Report (Rate)",
        columns,
        rows,
        format: { table: { scrollable: true, maxHeight: 800 } },
      };
    },

    /** Main trigger: builds and emits report tables based on selected options. */
    generateReport() {
      this.$message({ message: "Generating Student Report...", type: "success" });
      const selectedStudents = this.getSelectedStudents();

      let tables = [];
      if (this.separateTables) {
        const privateStudents = selectedStudents.filter(
          (s) => s.private_classes_total > 0
        );
        const groupStudents = selectedStudents.filter(
          (s) => s.group_classes_total > 0
        );
        if (this.displayMode === "count") {
          tables = [
            this.buildCountTable(privateStudents, "private"),
            this.buildCountTable(groupStudents, "group"),
          ];
        } else {
          tables = [
            this.buildRateTable(privateStudents, "private"),
            this.buildRateTable(groupStudents, "group"),
          ];
        }
      } else {
        tables = [
          this.displayMode === "count"
            ? this.buildCountTable(selectedStudents, "all")
            : this.buildRateTable(selectedStudents, "all"),
        ];
      }

      this.$emit("report-generated", tables);
    },
  },
};
</script>

<style scoped>
