  display: flex;
  flex-direction: column;
  align-items: flex-start;
  justify-content: flex-start;
  gap: 12px;
  padding: 16px;
  width: 100%;
  box-sizing: border-box;
}

.settings-form {
  display: flex;
  flex-direction: column;
  align-items: flex-start;
  justify-content: flex-start;
  gap: 8px;
  width: 100%;
  box-sizing: border-box;
}

.title {
  font-weight: 600;
  font-size: 18px;
  color: #374151;
}

/* === Label above inputs/radios === */
.label-above,
.label-above-checkbox {
  display: flex;
  flex-direction: column;
