import * as XLSX from "xlsx";
import { saveAs } from "file-saver";

/**
 * ===========================================================
 * Utility: exportToExcel
 * -----------------------------------------------------------
 * Description:
 *   Exports one or more report tables into a single Excel (.xlsx)
 *   workbook, with each table represented as a separate sheet.
 *
 *   Used for structured multi-table exports — e.g., when teachers
 *   generate both “Overview” and “User Averages” reports together.
 *
 * Usage:
 *   exportToExcel(tables, disabledCols, disabledRows)
 *
 * Parameters:
 *   @param {Array} tables - Array of report table objects:
 *        [
 *          {
 *            title: "Sheet Name",
 *            columns: [{ label: "Header", key: "headerKey" }, ...],
 *            rows: [{ headerKey: "Value", ... }, ...]
 *          },
 *          ...
 *        ]
 *
 *   @param {Array} [disabledCols=[]]
 *        Array of column keys to exclude from export.
 *
 *   @param {Array} [disabledRows=[]]
 *        Array of row indices to exclude from export.
 *
 * Output:
 *   - Generates a single Excel file named `Report_<date>.xlsx`
 *   - Each table becomes a separate sheet (max 31 characters per name)
 *   - Preserves column order and row filtering
 *
 * Dependencies:
 *   - xlsx (SheetJS) → For workbook creation
 *   - file-saver → For triggering download in browser
 * ===========================================================
 */

export function exportToExcel(tables, disabledCols = [], disabledRows = []) {
  try {
    // Create a new empty Excel workbook
    const workbook = XLSX.utils.book_new();

    tables.forEach((table) => {
      // Filter active columns (exclude disabled ones)
      const activeColumns = table.columns.filter(
        (c) => !disabledCols.includes(c.key)
      );

      // Create header row
      const headers = activeColumns.map((c) => c.label);

      // Build rows with only active columns and non-disabled rows
      const rows = table.rows
        .filter((_, i) => !disabledRows.includes(i))
        .map((r) =>
          activeColumns.map((c) => (r[c.key] !== undefined ? r[c.key] : ""))
        );

      // Convert data array to Excel sheet
      const sheet = XLSX.utils.aoa_to_sheet([headers, ...rows]);

      // Append sheet to workbook (Excel limits sheet names to 31 chars)
      XLSX.utils.book_append_sheet(
        workbook,
        sheet,
        table.title.slice(0, 31)
      );
    });

    // Write workbook to binary array and create download blob
    const wbout = XLSX.write(workbook, { bookType: "xlsx", type: "array" });
    const date = new Date().toISOString().slice(0, 10);

    saveAs(
      new Blob([wbout], { type: "application/octet-stream" }),
      `Report_${date}.xlsx`
    );
  } catch (err) {
    console.error("Excel export failed:", err);
  }
}
