<!--
  ==========================================================
  Component: CourseReport.vue
  Description:
    Configuration panel for generating course-level reports.
    Provides report type options (Overview, Detail, Fundae, ANPAL),
    a course selector (for Detail-type reports), and an option
    to include or exclude cancelled classes.

  Responsibilities:
    - Collect user preferences for report generation.
    - Aggregate and summarise course-level data.
    - Build detailed class-level tables when requested.
    - Emit formatted tables to parent (App.vue) for rendering.

  Data Sources:
    - combined.json → per-class aggregated data
    - globalSettings.js → shared configuration (optional future use)

  Notes:
    - Fundae and ANPAL report types are disabled placeholders.
    - This version focuses on Overview and Detail generation.
    - The includeCancelled option filters class inclusion logic.
  ==========================================================
-->

<template>
  <div class="course-report-settings">
    <h3 class="title">Course Report</h3>

    <!-- ======= REPORT OPTIONS ======= -->
    <el-form label-position="left" label-width="160px">
      <!-- Report Type -->
      <el-form-item label="Report Type">
        <el-radio-group v-model="reportType">
          <el-radio label="overview">Overview</el-radio>
          <el-radio label="detail">Detail</el-radio>
          <el-radio label="fundae">Fundae</el-radio>
          <el-radio label="anpal">ANPAL</el-radio>
        </el-radio-group>
      </el-form-item>

      <!-- Include Cancelled -->
      <el-form-item label="Include cancelled classes">
        <el-checkbox v-model="includeCancelled"></el-checkbox>
      </el-form-item>

      
      <!-- Course Selector (visible for Detail/Fundae/ANPAL) -->
        <el-form-item v-if="['detail', 'fundae', 'anpal'].includes(reportType)" label="Course ID:">
        <el-select
            v-model="selectedCourseId"
            placeholder="Type or select course"
            size="small"
            filterable
            clearable
            :filter-method="filterCourses"
        >
            <el-option
            v-for="id in filteredCourseIds"
            :key="id"
            :label="id"
            :value="id"
            />
        </el-select>
        </el-form-item>

        <!-- Course Finder Button -->
        <el-form-item v-if="['detail', 'fundae', 'anpal'].includes(reportType)">
        <el-button size="small" type="default" @click="$emit('open-course-finder')">
            Find My Course ID
        </el-button>
        </el-form-item>

    </el-form>

    <!-- Generate Report -->
    <el-button type="primary" size="medium" @click="generateReport">
      Generate Report
    </el-button>
  </div>
</template>

<script>
import combinedData from "@/data/combined.json";
import { globalSettings } from "@/store/globalSettings";

export default {
  name: "CourseReport",

  data() {
    return {
      reportType: "overview",
      includeCancelled: false,
      selectedCourseId: null,
      searchQuery: ""
    };
  },

  computed: {
    /** Returns a list of unique course IDs from combined data. */
    uniqueCourseIds() {
      const ids = [...new Set(combinedData.map(c => c.course_id).filter(Boolean))];
      return ids.sort((a, b) => a - b);
    },

    filteredCourseIds() {
    if (!this.searchQuery) return this.uniqueCourseIds;
    const query = this.searchQuery.toString().toLowerCase();
    return this.uniqueCourseIds.filter(id =>
        id.toString().toLowerCase().includes(query)
    );
    },

  },

  

  methods: {

    /** Custom filter method for the course dropdown. */
    filterCourses(query) {
    this.searchQuery = query;
    },

    /** Formats date string (YYYY-MM-DD HH:mm:ss) → YYYY-MM-DD. */
    formatDate(datetime) {
      if (!datetime) return "";
      return datetime.split(" ")[0];
    },

    /** Extracts time (HH:MM) from a datetime string. */
    formatTime(datetime) {
      if (!datetime) return "";
      try {
        // Handles both ISO and SQL-like formats
        const timePart = datetime.split(" ")[1] || datetime;
        const [hour, minute] = timePart.split(":");
        return `${hour}:${minute}`;
      } catch {
        return "";
      }
    },

    /** Extracts time (HH:MM) from a full datetime string. */
    extractTime(datetime) {
    if (!datetime) return "–";
    try {
        // Works for both ISO and SQL-style timestamps
        const timePart = datetime.split(" ")[1] || new Date(datetime).toTimeString();
        const [hour, minute] = timePart.split(":");
        return `${hour}:${minute}`;
    } catch {
        return "–";
    }
    },

    /** Calculates attendance rate (attended participants ÷ total seats). */
    calcAttendanceRate(classes) {
      const totalSeats = classes.reduce((sum, c) => sum + (c.available_seats || 0), 0);
      const attended = classes.reduce(
        (sum, c) =>
          sum +
          c.participants.filter(p => !p.isteacher && p.attended).length,
        0
      );
      return totalSeats ? (attended / totalSeats).toFixed(2) : "–";
    },

      /** Allows parent to set the selected course id (from CourseFinder). */
    setSelectedCourse(courseId) {
        this.selectedCourseId = courseId;
    },

    /**
     * Builds the Overview table.
     * Each row represents a unique course with summary information.
     * @param {Array} data - Combined class records
     * @returns {Object} Structured table object
     */
    buildOverviewTable(data) {
      const courses = [...new Set(data.map(c => c.course_id))];

      const rows = courses.map(courseId => {
        const courseClasses = data.filter(
          c => c.course_id === courseId && (this.includeCancelled || !c.is_cancelled)
        );

        if (courseClasses.length === 0) return null;

        const teachers = [
          ...new Set(
            courseClasses.flatMap(c =>
              c.participants
                .filter(p => p.isteacher)
                .map(p => p.username)
            )
          )
        ];

        const teacherNames = [
          ...new Set(
            courseClasses.flatMap(c =>
              c.participants
                .filter(p => p.isteacher)
                .map(p => `${p.first_name || ""} ${p.last_name || ""}`.trim())
            )
          )
        ];

        const startDate = this.formatDate(
          courseClasses.reduce(
            (min, c) =>
              !min || new Date(c.scheduled_start) < new Date(min)
                ? c.scheduled_start
                : min,
            null
          )
        );

        const endDate = this.formatDate(
          courseClasses.reduce(
            (max, c) =>
              !max || new Date(c.scheduled_start) > new Date(max)
                ? c.scheduled_start
                : max,
            null
          )
        );

        const levels = [...new Set(courseClasses.map(c => c.lang_level).filter(Boolean))];
        const subjects = [...new Set(courseClasses.map(c => c.class_lang).filter(Boolean))];
        const descriptions = [...new Set(courseClasses.map(c => c.class_notes).filter(Boolean))];
        const seats = Math.max(...courseClasses.map(c => c.available_seats || 0));
        const uniqueStudents = [
          ...new Set(
            courseClasses.flatMap(c =>
              c.participants.filter(p => !p.isteacher).map(p => p.username)
            )
          )
        ];

        const attendanceRate = this.calcAttendanceRate(courseClasses);

        return {
          course_id: courseId,
          teacher_username: teachers.join(", "),
          teacher_name: teacherNames.join(", "),
          start_date: startDate,
          end_date: endDate,
          level: levels.join(", "),
          subject: subjects.join(", "),
          course_description: descriptions.join(", "),
          total_classes: courseClasses.length,
          seats,
          students_enrolled: uniqueStudents.length,
          attendance_rate: attendanceRate
        };
      }).filter(Boolean);

      return {
        title: "Course Overview",
        columns: [
          { label: "Course ID", key: "course_id" },
          { label: "Teacher Username", key: "teacher_username" },
          { label: "Teacher Name", key: "teacher_name" },
          { label: "Start Date", key: "start_date" },
          { label: "End Date", key: "end_date" },
          { label: "Level", key: "level" },
          { label: "Subject", key: "subject" },
          { label: "Course Description", key: "course_description" },
          { label: "Total Classes", key: "total_classes" },
          { tooltip: "Total available student spaces in the class", label: "Seats", key: "seats" },
          { label: "Students Enrolled", key: "students_enrolled" },
          { tooltip: "Excluding cancelled classes. 1 = 100%", label: "Attendance Rate", key: "attendance_rate" }
        ],
        rows,
        format: {
          table: { scrollable: true, maxHeight: 800, freezeHeader: true }
        }
      };
    },

    /**
     * Builds the Detail report.
     * Generates two tables: course summary and class list.
     * @param {Array} data - Combined data
     * @param {Number|String} courseId - Selected course ID
     * @returns {Array} Array of structured tables
     */
    buildDetailTables(data, courseId) {
      const courseClasses = data
        .filter(c => c.course_id === courseId && (this.includeCancelled || !c.is_cancelled))
        .sort((a, b) => new Date(a.scheduled_start) - new Date(b.scheduled_start));

      if (!courseClasses.length) return [];

      // === 1️⃣ Course Summary Table ===
      const overview = this.buildOverviewTable(data);
      const courseRow = overview.rows.find(r => r.course_id === courseId);
      const summaryTable = {
        ...overview,
        title: `Course Summary: ${courseId}`,
        rows: [courseRow]
      };

      // === 2️⃣ Class List Table ===
      const allStudents = [
        ...new Set(
          courseClasses.flatMap(c =>
            c.participants.filter(p => !p.isteacher).map(p => p.username)
          )
        )
      ];

      const rows = courseClasses.map((cls, idx) => {
        const row = {
          class_number: `Class ${idx + 1}`,
          date: this.formatDate(cls.scheduled_start),
          time: this.formatTime(cls.scheduled_start),
          duration: cls.scheduled_duration,
        };

        if (this.includeCancelled) {
          row.status = cls.is_cancelled ? "Cancelled" : "Completed";
        }

        allStudents.forEach(username => {
          const student = cls.participants.find(p => p.username === username);
          if (!student) {
            row[username] = "–";
          } else if (student.is_cancelled) {
            row[username] = "Cancelled";
          } else if (student.attended) {
            row[username] = "Attended";
          } else {
            row[username] = "No Show";
          }
        });

        return row;
      });

      const columns = [
        { label: "Class", key: "class_number" },
        { label: "Date", key: "date" },
        { label: "Time", key: "time" },
        { label: "Duration", key: "duration" },
      ];

      if (this.includeCancelled) {
        columns.push({ label: "Status", key: "status" });
      }

      allStudents.forEach(username => {
        columns.push({ label: username, key: username });
      });

      const classListTable = {
        title: `Class List: ${courseId}`,
        columns,
        rows,
        format: {
          table: { scrollable: true, maxHeight: 800, freezeHeader: true }
        }
      };

      return [summaryTable, classListTable];
    },



    /**
     * Builds the Fundae report tables.
     * Includes course summary, class list, and an aggregated student attendance table.
     * @param {Array} data - Combined class data
     * @param {Number|String} courseId - Selected course ID
     * @returns {Array} Array of structured tables
     */
    buildFundaeTables(data, courseId) {
      // === Filter classes according to includeCancelled ===
      const courseClasses = data
        .filter(c => c.course_id === courseId && (this.includeCancelled || !c.is_cancelled))
        .sort((a, b) => new Date(a.scheduled_start) - new Date(b.scheduled_start));

      if (!courseClasses.length) return [];

      // === 1️⃣ Reuse Summary and Class List from Detail Report ===
      const [summaryTable, classListTable] = this.buildDetailTables(data, courseId);

      // === 2️⃣ Build Student Attendance Table ===
      const studentMap = {};

      courseClasses.forEach(cls => {
        cls.participants
          .filter(p => !p.isteacher)
          .forEach(p => {
            const username = p.username;
            if (!studentMap[username]) {
              studentMap[username] = {
                username,
                name: `${p.first_name || ""} ${p.last_name || ""}`.trim(),
                enrolled: 0,
                attended: 0,
                no_show: 0,
                cancelled: 0
              };
            }

            // Count this class if it’s not globally cancelled (or includeCancelled = true)
            studentMap[username].enrolled++;

            if (p.is_cancelled) {
              studentMap[username].cancelled++;
            } else if (p.attended) {
              studentMap[username].attended++;
            } else {
              studentMap[username].no_show++;
            }
          });
      });

      // === 3️⃣ Calculate Attendance Rates ===
      const studentRows = Object.values(studentMap).map(s => ({
        ...s,
        attendance_rate: s.enrolled
          ? (s.attended / s.enrolled).toFixed(2)
          : "–"
      }));

      const studentAttendanceTable = {
        title: `Student Attendance: ${courseId}`,
        columns: [
          { label: "Username", key: "username" },
          { label: "Name", key: "name" },
          { label: "Enrolled", key: "enrolled" },
          { label: "Attended", key: "attended" },
          { label: "No Show", key: "no_show" },
          { label: "Cancelled", key: "cancelled" },
          { tooltip: "Excluding cancelled classes. 1 = 100%", label: "Attendance Rate", key: "attendance_rate" }
        ],
        rows: studentRows,
        format: {
          table: { scrollable: true, maxHeight: 800, freezeHeader: true }
        }
      };

      // === 4️⃣ Return all three tables together ===
      return [summaryTable, classListTable, studentAttendanceTable];
    },



    /**
     * Builds the ANPAL report tables.
     * Similar to Fundae but includes an expanded class list table
     * with teacher and class-level metadata for compliance exports.
     * @param {Array} data - Combined class data
     * @param {Number|String} courseId - Selected course ID
     * @returns {Array} Array of structured tables
     */
    buildAnpalTables(data, courseId) {
      // === Filter classes according to includeCancelled ===
      const courseClasses = data
        .filter(c => c.course_id === courseId && (this.includeCancelled || !c.is_cancelled))
        .sort((a, b) => new Date(a.scheduled_start) - new Date(b.scheduled_start));

      if (!courseClasses.length) return [];

      // === 1️⃣ Reuse Summary and Student Attendance from Fundae ===
      const [summaryTable] = this.buildDetailTables(data, courseId);
      const [, , studentAttendanceTable] = this.buildFundaeTables(data, courseId);

      // === 2️⃣ Build ANPAL-specific Class List Table ===
      const allStudents = [
        ...new Set(
          courseClasses.flatMap(c =>
            c.participants.filter(p => !p.isteacher).map(p => p.username)
          )
        )
      ];

      const rows = courseClasses.map((cls, idx) => {
        // Find teacher info
        const teacher = cls.participants.find(p => p.isteacher);
        const teacherUsername = teacher ? teacher.username : "–";
        const teacherName = teacher
          ? `${teacher.first_name || ""} ${teacher.last_name || ""}`.trim()
          : "–";
        const teacherTime = this.extractTime(teacher?.attended_time) || "–";

        const row = {
          class_number: `Class ${idx + 1}`,
          date: this.formatDate(cls.scheduled_start),
          time: this.formatTime(cls.scheduled_start),
          class_end_time: this.formatTime(cls.actual_end),
          class_id: cls.slug,
          teacher_username: teacherUsername,
          teacher_name: teacherName,
          teacher_attended_time: teacherTime
        };

        if (this.includeCancelled) {
          row.status = cls.is_cancelled ? "Cancelled" : "Completed";
        }

        // Add student attendance columns
        allStudents.forEach(username => {
          const student = cls.participants.find(p => p.username === username);
          if (!student) {
            row[username] = "–";
          } else if (student.is_cancelled) {
            row[username] = "Cancelled";
          } else if (student.attended) {
            // show attended_time instead of just 'Attended'
            row[username] = this.extractTime(student.attended_time) || "Attended";
          } else {
            row[username] = "No Show";
          }
        });

        return row;
      });

      // === 3️⃣ Define Table Columns ===
      const columns = [
        { label: "Class", key: "class_number" },
        { label: "Date", key: "date" },
        { label: "Time", key: "time" },
        { label: "Class End Time", key: "class_end_time" }
      ];

      if (this.includeCancelled) {
        columns.push({ label: "Status", key: "status" });
      }

      columns.push(
        { label: "Class ID", key: "class_id" },
        { label: "Teacher Username", key: "teacher_username" },
        { label: "Teacher Name", key: "teacher_name" },
        { label: "Teacher Attended Time", key: "teacher_attended_time" }
      );

      allStudents.forEach(username => {
        columns.push({ label: username, key: username });
      });

      const anpalClassListTable = {
        title: `ANPAL Class List: ${courseId}`,
        columns,
        rows,
        format: {
          table: { scrollable: true, maxHeight: 800, freezeHeader: true }
        }
      };

      // === 4️⃣ Return all three tables ===
      return [summaryTable, anpalClassListTable, studentAttendanceTable];
    },



    /**
     * Main trigger for generating the Course Report.
     * Builds Overview or Detail tables based on user selection.
     */
    generateReport() {
      this.$message({ message: "Generating Course Report...", type: "success" });

      let results = [];

      if (this.reportType === "overview") {
        results.push(this.buildOverviewTable(combinedData));
      } else if (this.reportType === "detail" && this.selectedCourseId) {
        results = this.buildDetailTables(combinedData, this.selectedCourseId);
      } else if (this.reportType === "fundae" && this.selectedCourseId) {
        results = this.buildFundaeTables(combinedData, this.selectedCourseId);
      } else if (this.reportType === "anpal" && this.selectedCourseId) {
        results = this.buildAnpalTables(combinedData, this.selectedCourseId);
      }

      this.$emit("report-generated", results);
    }
  }
};
</script>

<style scoped>
.course-report-settings {
  display: flex;
  flex-direction: column;
  align-items: flex-start;
  justify-content: flex-start;
  gap: 12px;
  padding: 16px;
  width: 100%;
  box-sizing: border-box;
}

.title {
  font-weight: 600;
  font-size: 18px;
  color: #374151;
}

.el-form {
  width: 100%;
  box-sizing: border-box;
}

.el-form-item {
  width: 100%;
}
</style>

