<!--
  ==========================================================
  Component: Settings.vue
  Description:
    Global Settings panel displayed in the right-side drawer of the reporting dashboard.
    Allows users to adjust prototype-level configuration options such as cancellation window,
    tardiness buffer, and primary color. These settings are bound to a shared global store
    (globalSettings.js), enabling other components to reactively access and use the same values.

  Notes:
    - This component currently serves as a placeholder UI for demonstration purposes.
    - Future iterations may include validation, persistence, and API syncing for these settings.
  ==========================================================
-->

<template>
  <div class="settings-container">
    <h3 class="settings-title">Global Settings</h3>

    <!-- Cancellation Window -->
    <div class="setting-item">
      <label class="setting-label">
        Cancellation Window (hours)
        <el-tooltip
          content="How many hours’ notice do students need to cancel their class in order to receive a refund"
          placement="top"
        >
          <i class="el-icon-info"></i>
        </el-tooltip>
      </label>
      <el-input
        v-model.number="settings.cancellationWindow"
        type="number"
        placeholder="24"
        min="0"
      />
    </div>

    <!-- School Primary Color -->
    <div class="setting-item">
      <label class="setting-label">
        School Primary Color
        <el-tooltip
          content="The school's primary color"
          placement="top"
        >
          <i class="el-icon-info"></i>
        </el-tooltip>
      </label>
      <el-input
        v-model="settings.primaryColor"
        placeholder="#111111"
        @input="validateHex"
      />
    </div>
  </div>
</template>

<script>
import { globalSettings } from "@/store/globalSettings";

export default {
  name: "Settings",

  data() {
    return {
      // Directly binds to the global reactive settings object
      // This allows updates made here to be reflected across the app in real time
      settings: globalSettings,
    };
  },

  methods: {
    /**
     * Validates the primary color input to ensure it is a valid 6-digit hexadecimal color.
     * Displays a warning message if the format is incorrect.
     * @param {String} value - The hex color string entered by the user.
     */
    validateHex(value) {
      const hexPattern = /^#([0-9A-Fa-f]{6})$/;
      if (!hexPattern.test(value)) {
        this.$message.warning("Please enter a valid 6-digit hex color code, e.g. #123ABC");
      }
    },
  },
};
</script>

