<template>
  <div class="teacher-hour-settings">
    <h3 class="title">Teacher Hour Count Report</h3>

    <el-form class="settings-form">
      <!-- ======= INCLUDE CLASSES ======= -->
      <el-form-item>
        <div class="label-above">
          <span>Include</span>
          <div class="checkbox-group">
            <el-checkbox v-model="includePrivate">Private Classes</el-checkbox>
            <el-checkbox v-model="includeGroup">Group Classes</el-checkbox>
          </div>
        </div>
      </el-form-item>

      <hr />

      <!-- ======= SEPARATE TABLES ======= -->
      <el-form-item>
        <div class="label-above-checkbox">
          <span>Separate Private and Group Classes</span>
          <el-checkbox v-model="separateTables" size="small"></el-checkbox>
        </div>
      </el-form-item>

      <hr />

      <!-- ======= SEPARATE BY DURATION ======= -->
      <el-form-item>
        <div>
          <span>Separate by Duration </span>
          <el-checkbox v-model="separateByDuration" size="small"></el-checkbox>

          <div v-if="separateByDuration" class="nested-section">
            <div class="checkbox-column">
              <el-checkbox
                v-for="duration in sortedDurations"
                :key="duration"
                v-model="durations[duration]"
              >
                {{ duration }} minutes
              </el-checkbox>
            </div>

            <el-button
              type="primary"
              size="small"
              class="select-all-btn"
              @click="selectAllDurations"
            >
              {{ allDurationsSelected ? "Unselect All" : "Select All" }}
            </el-button>
          </div>
        </div>
      </el-form-item>

      <hr />

      <!-- ======= PENALTIES ======= -->
      <el-form-item>
        <div>
          <span>Penalize Tardiness </span>
          <el-checkbox v-model="penalizeTardiness" size="small"></el-checkbox>

          <div v-if="penalizeTardiness" class="nested-section">
            <div class="label-above-checkbox">
              <span>Tardiness Limit (minutes)</span>
              <el-input-number
                v-model="tardinessLimit"
                :min="1"
                :max="60"
                size="small"
              />
            </div>

            <div class="radio-group">
              <el-radio-group v-model="tardinessMode">
                <el-radio label="full">Full Class Deducted</el-radio>
                <el-radio label="partial">Partial Deduction</el-radio>
              </el-radio-group>
            </div>

            <div
              v-if="tardinessMode === 'partial'"
              class="label-above-checkbox"
            >
              <span>Deduction Percentage</span>
              <el-input-number
                v-model="tardinessPercent"
                :min="1"
                :max="100"
                size="small"
              />
            </div>
          </div>

          <!-- Penalize Teacher No-Shows -->
          <div style="margin-top: 8px;">
            <span>Penalize Teacher No-Shows </span>
            <el-checkbox v-model="penalizeTeacherNoShow" size="small"></el-checkbox>
          </div>
        </div>
      </el-form-item>

      <hr />

      <!-- ======= PAY FOR LATE CANCELLATIONS ======= -->
      <el-form-item>
        <div>
          <span>Pay for Late Cancellations </span>
          <el-checkbox v-model="payLateCancellations" size="small"></el-checkbox>

          <div v-if="payLateCancellations" class="nested-section">
            <div class="label-above-checkbox">
              <span>Cancellation Window (hours)</span>
              <el-input-number
                v-model="cancellationWindow"
                :min="1"
                :max="72"
                size="small"
              />
            </div>

            <div class="radio-group">
              <el-radio-group v-model="cancellationPayMode">
                <el-radio label="full">Full Class</el-radio>
                <el-radio label="partial">Partial Class</el-radio>
              </el-radio-group>
            </div>

            <div
              v-if="cancellationPayMode === 'partial'"
              class="label-above-checkbox"
            >
              <span>Payment Percentage</span>
              <el-input-number
                v-model="cancellationPayPercent"
                :min="1"
                :max="100"
                size="small"
              />
            </div>
          </div>
        </div>
      </el-form-item>

      <hr />

      <!-- ======= PAY FOR STUDENT NO-SHOWS ======= -->
      <el-form-item>
        <div>
          <span>Pay for Student No-Shows </span>
          <el-checkbox v-model="payNoShows" size="small"></el-checkbox>

          <div v-if="payNoShows" class="nested-section">
            <div class="radio-group">
              <el-radio-group v-model="noShowMode">
                <el-radio label="full">Full Class</el-radio>
                <el-radio label="partial">Partial Class</el-radio>
              </el-radio-group>
            </div>

            <div
              v-if="noShowMode === 'partial'"
              class="label-above-checkbox"
            >
              <span>Payment Percentage</span>
              <el-input-number
                v-model="noShowPercent"
                :min="1"
                :max="100"
                size="small"
              />
            </div>
          </div>
        </div>
      </el-form-item>

      <hr />

      <!-- ======= GENERATE BUTTON ======= -->
      <el-form-item>
        <el-button type="primary" size="medium" @click="generateReport">
          Generate Report
        </el-button>
      </el-form-item>
    </el-form>
  </div>
</template>

<script>
/**
 * ===========================================================
 * Component: TeacherHourCountReport.vue
 * Description:
 *   Generates teacher hour-count tables summarising class counts,
 *   attendance, lateness, cancellations, and pay-adjusted totals.
 *   Supports splitting by class type and duration.
 * ===========================================================
 */

import combinedData from "@/data/combined.json";
import { globalSettings } from "@/store/globalSettings";

/* ---------------- Helper functions ---------------- */
function add(a, b) {
  return (Number(a) || 0) + (Number(b) || 0);
}
function minsToHours(mins) {
  return Math.round((mins / 60) * 100) / 100;
}

export default {
  name: "TeacherHourCountReport",

  data() {
    return {
      includePrivate: true,
      includeGroup: true,
      separateTables: false,
      separateByDuration: false,
      durations: {},

      penalizeTardiness: false,
      tardinessLimit: 5,
      tardinessMode: "full",
      tardinessPercent: 50,
      penalizeTeacherNoShow: false,

      payLateCancellations: false,
      cancellationPayMode: "full",
      cancellationPayPercent: 50,

      payNoShows: false,
      noShowMode: "full",
      noShowPercent: 50,
    };
  },

  computed: {
    cancellationWindow: {
      get() {
        return globalSettings.cancellationWindow;
      },
      set(value) {
        globalSettings.cancellationWindow = value;
      },
    },
    sortedDurations() {
      return Object.keys(this.durations)
        .map(Number)
        .sort((a, b) => a - b)
        .map(String);
    },
    allDurationsSelected() {
      const keys = Object.keys(this.durations);
      return keys.length && keys.every((k) => this.durations[k] === true);
    },
  },

  mounted() {
    this.loadDurations();
  },

  methods: {
    loadDurations() {
      const uniqueDurations = new Set();
      combinedData.forEach((cls) => {
        if (cls.scheduled_duration != null) uniqueDurations.add(cls.scheduled_duration);
      });
      this.durations = Array.from(uniqueDurations)
        .sort((a, b) => a - b)
        .reduce((acc, d) => {
          acc[String(d)] = false;
          return acc;
        }, {});
    },

    selectAllDurations() {
      const shouldSelect = !this.allDurationsSelected;
      Object.keys(this.durations).forEach((key) => (this.durations[key] = shouldSelect));
    },

    generateReport() {
      this.$message({ message: "Generating Teacher Hour Count Report...", type: "success" });
      const data = combinedData.filter((cls) => {
        const isPrivate = cls.available_seats === 1;
        return (
          (this.includePrivate && isPrivate) ||
          (this.includeGroup && !isPrivate)
        );
      });
      const tables = this.buildTables(data);
      this.$emit("report-generated", tables);
    },

    buildTables(data) {
      const durationsSelected = Object.keys(this.durations).filter((d) => this.durations[d]);
      const tables = [];
      const types = this.separateTables ? ["private", "group"] : [null];
      const durSets = this.separateByDuration ? [...durationsSelected, "other"] : [null];

      types.forEach((type) => {
        durSets.forEach((dur) => {
          const subset = data.filter((cls) => {
            const isPrivate = cls.available_seats === 1;
            const typeMatch = !this.separateTables || (type === "private" ? isPrivate : !isPrivate);
            const durMatch = !this.separateByDuration
              ? true
              : durationsSelected.includes(String(cls.scheduled_duration))
              ? dur === String(cls.scheduled_duration)
              : dur === "other";
            return typeMatch && durMatch;
          });
          if (!subset.length) return;

          const titleParts = [];
          if (type) titleParts.push(type === "private" ? "Private" : "Group");
          if (dur && dur !== "other") titleParts.push(`${dur}-Minute`);
          if (dur === "other") titleParts.push("Other Durations");
          const title = titleParts.length ? `${titleParts.join(" ")} Teacher Hours` : "Teacher Hours";

          tables.push(this.buildTeacherHoursTable(subset, title));
        });
      });

      return tables;
    },

    buildTeacherHoursTable(classes, title) {
      const teacherMap = {};

      classes.forEach((cls) => {
        const teacher = cls.participants.find((p) => p.isteacher);
        if (!teacher) return;
        const tKey = teacher.username || "unknown";
        if (!teacherMap[tKey]) {
          teacherMap[tKey] = {
            teacher_name: [teacher.first_name, teacher.last_name].filter(Boolean).join(" ") || "—",
            teacher_username: tKey,
            class_count: 0,
            hour_scheduled: 0,
            hour_actual: 0,
            attended: 0,
            attended_late: 0,
            student_no_show: 0,
            late_cancellation: 0,
            total_cancelled: 0,
            teacher_no_show: 0,
            total_classes: 0,
          };
        }

        const row = teacherMap[tKey];
        row.total_classes++;

        const tardiness = teacher.tardiness ?? 0;
        const wasLate = this.penalizeTardiness && tardiness > this.tardinessLimit;
        const teacherAttended = !!teacher.attended;
        const students = cls.participants.filter((p) => !p.isteacher);
        const studentsAttended = students.filter((s) => s.attended).length;
        const studentNoShow = studentsAttended === 0 && teacherAttended;
        const cancelled = cls.is_cancelled;
        const cancelledByStudent = !!cls.cancelled_by_student;
        const cancelledByTeacher = !!cls.cancelled_by_teacher;

        let lateCancel = false;
        if (cancelled && cancelledByStudent && cls.cancelled_interval != null) {
          lateCancel = cls.cancelled_interval < this.cancellationWindow * 60;
        }

        const teacherNoShow = !teacherAttended && !cancelled;

        // Scheduled and actual durations
        let scheduledHrs = minsToHours(cls.scheduled_duration);
        let actualHrs = minsToHours(cls.actual_duration || cls.scheduled_duration);

        // === Apply penalties ===
        if (this.penalizeTardiness && wasLate) {
          if (this.tardinessMode === "full") actualHrs = 0;
          else actualHrs *= (100 - this.tardinessPercent) / 100;
        }
        if (this.penalizeTeacherNoShow && teacherNoShow) actualHrs = 0;

        if (this.payNoShows && studentNoShow) {
          if (this.noShowMode === "partial") actualHrs *= this.noShowPercent / 100;
        } else if (!this.payNoShows && studentNoShow) {
          actualHrs = 0;
        }

        if (cancelled) {
          if (this.payLateCancellations && lateCancel) {
            if (this.cancellationPayMode === "partial")
              actualHrs *= this.cancellationPayPercent / 100;
          } else {
            actualHrs = 0;
          }
        }

        // Aggregate
        row.class_count++;
        row.hour_scheduled = add(row.hour_scheduled, scheduledHrs);
        row.hour_actual = add(row.hour_actual, actualHrs);
        if (teacherAttended) row.attended++;
        if (wasLate) row.attended_late++;
        if (studentNoShow) row.student_no_show++;
        if (lateCancel) row.late_cancellation++;
        if (cancelled) row.total_cancelled++;
        if (teacherNoShow) row.teacher_no_show++;
      });

      // Columns (conditionally visible)
      const columns = [
        { label: "Teacher Name", key: "teacher_name" },
        { label: "Teacher Username", key: "teacher_username" },
        { label: "Class Count", key: "class_count" },
        { label: "Hour Count (Scheduled)", key: "hour_scheduled" },
        { label: "Hour Count (Actual)", key: "hour_actual" },
        { label: "Attended", key: "attended" },
        this.penalizeTardiness ? { tooltip: "Teacher entered class after the tardiness limit", label: "Attended Late", key: "attended_late" } : null,
        this.payNoShows ? { tooltip: "Classes where no studednts attended but the teacher did", label: "Student No-Shows", key: "student_no_show" } : null,
        this.payLateCancellations ? { tooltip: `Cancelled by the student in less than ${globalSettings.cancellationWindow} hours`, label: "Late Cancellation", key: "late_cancellation" } : null,
        { label: "Total Cancelled", key: "total_cancelled" },
        this.penalizeTeacherNoShow
          ? { label: "Teacher No-Shows", key: "teacher_no_show" }
          : null,
        { tooltip: "Includes cancelled classes.", label: "Total Classes Enrolled", key: "total_classes" },
      ].filter(Boolean);

      const rows = Object.values(teacherMap);
      return {
        title,
        columns,
        rows,
        format: { table: { scrollable: true, maxHeight: 800 } },
      };
    },
  },
};
</script>

