<!--
  ==========================================================
  Component: OverviewReport.vue
  Description:
    Configuration panel for generating the Overview Report.
    Provides form controls to select which summary tables to include
    and defines how time intervals should be displayed (hours, minutes, or days).

  Responsibilities:
    - Collect user input for report generation parameters.
    - Aggregate and summarise class and user data into structured tables.
    - Emit formatted tables to parent (App.vue) for rendering.

  Data Sources:
    - combined.json → per-class aggregated data
    - users.json → aggregated statistics per user
    - globalSettings.js → shared reactive configuration (cancellation window, etc.)

  Notes:
    - This component is primarily for demonstration and prototype reporting.
    - It statically imports JSON data; future versions may fetch data dynamically.
  ==========================================================
-->

<template>
  <div class="overview-settings">
    <h3 class="title">Overview Report</h3>

    <!-- ======= REPORT OPTIONS ======= -->
    <el-form label-position="left" label-width="140px">
      <!-- Select which summary tables to include -->
      <el-form-item label="Include Tables">
        <el-checkbox-group v-model="selectedTables">
          <el-checkbox label="overview">Class Summary</el-checkbox>
          <el-checkbox label="user">User Averages</el-checkbox>
        </el-checkbox-group>
      </el-form-item>

      <!-- Select unit for displaying time intervals -->
      <el-form-item label="Interval Units">
        <el-select v-model="intervalUnit" placeholder="Select Unit" size="small">
          <el-option label="Hours" value="hours" />
          <el-option label="Minutes" value="minutes" />
          <el-option label="Days" value="days" />
        </el-select>
      </el-form-item>
    </el-form>

    <!-- Generate report button -->
    <el-button type="primary" size="medium" @click="generateReport">
      Generate Report
    </el-button>
  </div>
</template>

<script>
import combinedData from "@/data/combined.json";
import usersData from "@/data/users.json";
import { globalSettings } from "@/store/globalSettings";

export default {
  name: "OverviewReport",

  data() {
    return {
      // Default report options
      selectedTables: ["overview", "user"],
      intervalUnit: "hours"
    };
  },

  methods: {
    /** Calculates the average of an array of numbers. */
    avg(arr) {
      return arr.length ? arr.reduce((a, b) => a + b, 0) / arr.length : 0;
    },

    /** Rounds a numeric value to 2 decimal places, or returns a dash if invalid. */
    round(val) {
      return val != null && !isNaN(val) ? Number(val.toFixed(2)) : "–";
    },

    /**
     * Converts a time value into the selected display unit.
     * - "minutes" multiplies hours by 60
     * - "days" divides hours by 24
     */
    convertInterval(value) {
      if (!value) return 0;
      if (this.intervalUnit === "minutes") return value * 60;
      if (this.intervalUnit === "days") return value / 24;
      return value;
    },

    /**
     * Builds the "Class Summary Overview" table.
     * Aggregates key statistics about private and group classes,
     * including totals, cancellations, attendance, and enrolment rates.
     * @param {Array} data - Array of class-level records from combined.json
     * @returns {Object} Structured table definition
     */
    buildCombinedOverviewTable(data) {
      const cancellationWindow = globalSettings.cancellationWindow * 60; // hours→minutes
      const priv = data.filter(c => c.available_seats === 1);
      const group = data.filter(c => c.available_seats > 1);

      // === Derived statistics ===

      // Attendance rate for private classes
      const privAttendanceRate = (() => {
        const totalStudents = priv.length;
        const attended = priv.filter(c =>
          c.participants.some(p => !p.isteacher && p.attended)
        ).length;
        return totalStudents ? (attended / totalStudents).toFixed(2) : "–";
      })();

      // Attendance rate for group classes
      const groupAttendanceRate = (() => {
        const allStudents = group.flatMap(c =>
          c.participants.filter(p => !p.isteacher)
        );
        const attended = allStudents.filter(p => p.attended);
        return allStudents.length
          ? (attended.length / allStudents.length).toFixed(2)
          : "–";
      })();

      // Enrolment rate for group classes
      const groupEnrol = (() => {
        const seats = group.reduce((sum, c) => sum + (c.available_seats || 0), 0);
        const enrolled = group.reduce((sum, c) => sum + (c.enrolled_students || 0), 0);
        return seats ? (enrolled / seats).toFixed(2) : "–";
      })();

      // === Table object returned to renderer ===
      return {
        title: "Class Summary Overview",
        columns: [
          { label: "", key: "label" },
          { label: "Private Classes", key: "private" },
          { label: "Group Classes", key: "group" }
        ],
        rows: [
          {
            tooltip: "Total number of classes within the report period",
            label: "Total classes",
            private: priv.length,
            group: group.length
          },
          {
            tooltip: "Classes which were not cancelled",
            label: "Completed classes",
            private: priv.filter(c => !c.is_cancelled).length,
            group: group.filter(c => !c.is_cancelled).length
          },
          {
            tooltip: "Total cancelled classes",
            label: "Cancelled classes",
            private: priv.filter(c => c.is_cancelled).length,
            group: group.filter(c => c.is_cancelled).length
          },
          {
            tooltip: "Cancelled by the class teacher",
            label: "Cancelled by teacher",
            private: priv.filter(c => c.cancelled_by_teacher).length,
            group: group.filter(c => c.cancelled_by_teacher).length
          },
          {
            tooltip: "Cancelled by neither student nor class teacher (admin cancellation)",
            label: "Cancelled by admin",
            private: priv.filter(c => c.cancelled_by_admin).length,
            group: group.filter(c => c.cancelled_by_admin).length
          },
          {
            tooltip: "Cancelled by the student (private classes only)",
            label: "Cancelled by student",
            private: priv.filter(c => c.cancelled_by_student).length,
            group: "–"
          },
          {
            tooltip: `Private classes cancelled in less than <${globalSettings.cancellationWindow}h.`,
            label: `Student cancelled <${globalSettings.cancellationWindow}h`,
            private: priv.filter(
              c =>
                c.cancelled_by_student &&
                c.cancelled_interval != null &&
                c.cancelled_interval < cancellationWindow
            ).length,
            group: "–"
          },
          {
            tooltip: "1.0 = 100%",
            label: "Attendance rate",
            private: privAttendanceRate,
            group: groupAttendanceRate
          },
          {
            tooltip: "1.0 = 100% (group classes only)",
            label: "Enrolment rate",
            private: "–",
            group: groupEnrol
          },
          {
            tooltip: "Classes the teacher didn't attend",
            label: "Teacher no show",
            private: priv.filter(
              c => !c.participants.some(p => p.isteacher && p.attended)
            ).length,
            group: group.filter(
              c => !c.participants.some(p => p.isteacher && p.attended)
            ).length
          },
          {
            tooltip: "Classes NO student attended",
            label: "Student no show",
            private: priv.filter(
              c => !c.participants.some(p => !p.isteacher && p.attended)
            ).length,
            group: group.filter(
              c => !c.participants.some(p => !p.isteacher && p.attended)
            ).length
          },
          {
            tooltip: "Classes nobody attended",
            label: "No show (both)",
            private: priv.filter(
              c => !c.participants.some(p => p.attended)
            ).length,
            group: group.filter(
              c => !c.participants.some(p => p.attended)
            ).length
          }
        ],
        format: {
          table: { scrollable: true, maxHeight: 800, freezeHeader: true },
          columns: {
            label: { width: 250, bold: true, freeze: true },
            private: { align: "center" },
            group: { align: "center" }
          }
        }
      };
    },

    /**
     * Builds the "User Averages" table.
     * Compares aggregated statistics between students and teachers
     * across the selected reporting period.
     * @param {Object} users - Preprocessed user data from users.json
     * @returns {Object} Structured table definition
     */
    buildUserAveragesTable(users) {
      const teachers = users.teachers || [];
      const students = users.students || [];

      // === Averages for teachers ===
      const teacherAvg = {
        total_classes: this.avg(teachers.map(t => t.total_classes)),
        total_attended: this.avg(teachers.map(t => t.total_attended)),
        total_cancelled: this.avg(teachers.map(t => t.total_cancelled)),
        total_teacher_cancelled: this.avg(teachers.map(t => t.total_teacher_cancelled)),
        total_student_cancelled: this.avg(teachers.map(t => t.total_student_cancelled)),
        average_cancellation_interval: this.avg(
          teachers.map(t => this.convertInterval(t.average_cancellation_interval))
        ),
        average_tardiness: this.avg(teachers.map(t => t.average_tardiness)),
        class_interval: this.avg(teachers.map(t => this.convertInterval(t.class_interval))),
        enrolment_interval: this.avg(
          teachers.map(t => this.convertInterval(t.enrolment_interval || 0))
        ),
        student_count: this.avg(teachers.map(t => t.student_count || 0)),
      };

      // === Averages for students ===
      const studentAvg = {
        total_classes: this.avg(students.map(s => s.total_classes)),
        total_attended: this.avg(students.map(s => s.total_attended)),
        total_cancelled: this.avg(students.map(s => s.total_cancelled)),
        total_teacher_cancelled: this.avg(students.map(s => s.total_teacher_cancelled)),
        total_student_cancelled: this.avg(students.map(s => s.total_student_cancelled)),
        average_cancellation_interval: this.avg(
          students.map(s => this.convertInterval(s.average_cancellation_interval))
        ),
        average_tardiness: this.avg(students.map(s => s.average_tardiness)),
        class_interval: this.avg(students.map(s => this.convertInterval(s.class_interval))),
        enrolment_interval: this.avg(
          students.map(s => this.convertInterval(s.enrolment_interval || 0))
        ),
        teacher_count: this.avg(students.map(s => s.teacher_count || 0)),
      };

      // === Derived metrics ===
      const teacherAttendanceRate = this.avg(
        teachers.map(t =>
          t.total_classes - t.total_cancelled > 0
            ? t.total_attended / (t.total_classes - t.total_cancelled)
            : 0
        )
      );
      const studentAttendanceRate = this.avg(
        students.map(s =>
          s.total_classes - s.total_cancelled > 0
            ? s.total_attended / (s.total_classes - s.total_cancelled)
            : 0
        )
      );

      const teacherAdminCancelled = this.avg(
        teachers.map(
          t => t.total_cancelled - (t.total_teacher_cancelled + t.total_student_cancelled)
        )
      );
      const studentAdminCancelled = this.avg(
        students.map(
          s => s.total_cancelled - (s.total_teacher_cancelled + s.total_student_cancelled)
        )
      );

      return {
        title: "User Averages",
        columns: [
          { label: "", key: "label" },
          { label: "Students", key: "students" },
          { label: "Teachers", key: "teachers" },
        ],
        rows: [
          { tooltip: "Average number of classes enrolled within the report period", label: "Average Total Classes", students: this.round(studentAvg.total_classes), teachers: this.round(teacherAvg.total_classes) },
          { tooltip: "Average number of classes each user attended", label: "Average Attended Classes", students: this.round(studentAvg.total_attended), teachers: this.round(teacherAvg.total_attended) },
          { label: "Average Cancellations (Total)", students: this.round(studentAvg.total_cancelled), teachers: this.round(teacherAvg.total_cancelled) },
          { label: "Average Cancellations by Student", students: this.round(studentAvg.total_student_cancelled), teachers: this.round(teacherAvg.total_student_cancelled) },
          { label: "Average Cancellations by Teacher", students: this.round(studentAvg.total_teacher_cancelled), teachers: this.round(teacherAvg.total_teacher_cancelled) },
          { label: "Average Cancellations by Admin", students: this.round(studentAdminCancelled), teachers: this.round(teacherAdminCancelled) },
          { tooltip: "Average time between cancellation and class start time", label: `Average Cancellation Interval (${this.intervalUnit})`, students: this.round(studentAvg.average_cancellation_interval), teachers: this.round(teacherAvg.average_cancellation_interval) },
          { label: "Average Attendance Rate", students: studentAttendanceRate.toFixed(2), teachers: teacherAttendanceRate.toFixed(2) },
          { tooltip: "Average number of minutes users are late for class (negative = early)", label: "Average Tardiness (min)", students: this.round(studentAvg.average_tardiness), teachers: this.round(teacherAvg.average_tardiness) },
          { tooltip: "Average time between enrolment and class start time", label: `Average Enrolment Interval (${this.intervalUnit})`, students: this.round(studentAvg.enrolment_interval), teachers: "–" },
          { tooltip: "Average time between classes (for multi-class users only)", label: `Average Class Interval (${this.intervalUnit})`, students: this.round(studentAvg.class_interval), teachers: this.round(teacherAvg.class_interval) },
          { tooltip: "Average number of unique students teachers have taught", label: "Average Students", students: "–", teachers: this.round(teacherAvg.student_count) },
          { tooltip: "Average number of unique teachers students have had", label: "Average Teachers", students: this.round(studentAvg.teacher_count), teachers: "–" },
        ],
        format: {
          table: { scrollable: true, maxHeight: 800, freezeHeader: true },
          columns: { label: { width: 350, bold: true, freeze: true }, students: { align: "center" }, teachers: { align: "center" } },
        },
      };
    },

    /**
     * Main trigger for generating the Overview Report.
     * Builds one or both summary tables depending on selected options,
     * and emits them to the parent for display.
     */
    generateReport() {
      this.$message({ message: "Generating Overview Report...", type: "success" });

      const results = [];
      if (this.selectedTables.includes("overview")) results.push(this.buildCombinedOverviewTable(combinedData));
      if (this.selectedTables.includes("user")) results.push(this.buildUserAveragesTable(usersData));

      this.$emit("report-generated", results);
    }
  }
};
</script>

<style scoped>
.overview-settings {
  display: flex;
  flex-direction: column;
  align-items: flex-start;
  justify-content: flex-start;
  gap: 12px;
  padding: 16px;
  width: 100%;
  box-sizing: border-box; /* ensures padding doesn’t shrink content area */
}

.title {
  font-weight: 600;
  font-size: 18px;
  color: #374151;
}

.el-form {
  width: 100%;
  box-sizing: border-box;
}

.el-form-item {
  width: 100%;
}

/* Make checkboxes wrap nicely on small screens */
.el-checkbox-group {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
}
</style>
